  sendDigits(callSid: CallSid, digits: string): Promise<void>;
  muteCall(callSid: CallSid): Promise<void>;
  unmuteCall(callSid: CallSid): Promise<void>;
}

export interface TelephonyCapabilities {
  readonly supportsStreaming: boolean;
  readonly supportsDigitDetection: boolean;
  readonly supportsCallRecording: boolean;
  readonly supportedCountries: readonly string[];
}

export interface TelephonyCallStatus {
  readonly callSid: CallSid;
  readonly status: 'queued' | 'ringing' | 'in-progress' | 'completed' | 'failed' | 'busy' | 'no-answer';
  readonly direction: 'inbound' | 'outbound';
  readonly durationSeconds: number;
}

export interface ISTTProvider {
  readonly name: string;
  readonly capabilities: STTCapabilities;
  ping(): Promise<HealthStatus>;
  transcribe(chunk: AudioChunk, config: STTConfig): Promise<STTResult>;
  openStream(config: STTConfig, onResult: (result: STTResult) => void): Promise<STTStreamHandle>;
}

export interface ISTTStreamingProvider extends ISTTProvider {
  readonly supportsStreaming: true;
  openStream(config: STTConfig, onResult: (result: STTResult) => void): Promise<STTStreamHandle>;
}

export interface ILLMProvider {
  readonly name: string;
  readonly capabilities: LLMCapabilities;
  ping(): Promise<HealthStatus>;
  complete(request: LLMRequest, config: LLMConfig): Promise<LLMResponse>;
}

export interface ILLMStreamingProvider extends ILLMProvider {
  readonly supportsStreaming: true;
  stream(
    request: LLMRequest,
    config: LLMConfig,
    onChunk: (chunk: LLMStreamChunk) => void
  ): Promise<LLMResponse>;
}

export interface ITTSProvider {
  readonly name: string;
  readonly capabilities: TTSCapabilities;
  ping(): Promise<HealthStatus>;
  synthesize(request: TTSRequest, config: TTSConfig): Promise<TTSResult>;
}

export interface ITTSStreamingProvider extends ITTSProvider {
  readonly supportsStreaming: true;
  synthesizeStream(
    request: TTSRequest,
    config: TTSConfig,
    onChunk: (chunk: TTSStreamChunk) => void
  ): Promise<TTSResult>;
}

import type { ITelephonyProvider, ISTTProvider, ILLMProvider, ITTSProvider } from '../interfaces/index.js';
import type { ProviderConfig } from '../config/index.js';
import type { ILogger } from '../logger/index.js';

export interface TelephonyProviderFactory {
  create(config: ProviderConfig['telephony'], logger: ILogger): ITelephonyProvider;
  readonly supportedProviders: readonly string[];
}

export interface STTProviderFactory {
  create(config: ProviderConfig['stt'], logger: ILogger): ISTTProvider;
  readonly supportedProviders: readonly string[];
}

export interface LLMProviderFactory {
  create(config: ProviderConfig['llm'], logger: ILogger): ILLMProvider;
  readonly supportedProviders: readonly string[];
}

export interface TTSProviderFactory {
  create(config: ProviderConfig['tts'], logger: ILogger): ITTSProvider;
  readonly supportedProviders: readonly string[];
}

export interface ProviderRegistry {
  telephony: TelephonyProviderFactory;
  stt: STTProviderFactory;
  llm: LLMProviderFactory;
  tts: TTSProviderFactory;
}

import type { VoiceEngineConfig } from './config/index.js';
import type { IEventBus } from './events/index.js';
import type { ILogger } from './logger/index.js';
import type { IMetricsCollector } from './metrics/index.js';
import type { ITelephonyProvider, ISTTProvider, ILLMProvider, ITTSProvider } from './interfaces/index.js';
import type { ReadyStatus } from './monitoring/index.js';
import type { ProviderRegistry } from './providers/index.js';

export interface VoiceEngineDependencies {
  readonly config: VoiceEngineConfig;
  readonly eventBus: IEventBus;
  readonly logger: ILogger;
  readonly metrics: IMetricsCollector;
  readonly telephonyProvider: ITelephonyProvider;
  readonly sttProvider: ISTTProvider;
  readonly llmProvider: ILLMProvider;
  readonly ttsProvider: ITTSProvider;
}

export interface VoiceEngine {
  readonly config: Readonly<VoiceEngineConfig>;
  readonly eventBus: IEventBus;
  readonly logger: ILogger;
  readonly metrics: IMetricsCollector;
  readonly telephony: ITelephonyProvider;
  readonly stt: ISTTProvider;
  readonly llm: ILLMProvider;
  readonly tts: ITTSProvider;
  readyStatus(): Promise<ReadyStatus>;
  shutdown(): Promise<void>;
}

export interface VoiceEngineFactory {
  create(dependencies: VoiceEngineDependencies): VoiceEngine;
}

export function createVoiceEngine(dependencies: VoiceEngineDependencies): VoiceEngine {
  const {
    config,
    eventBus,
    logger,
    metrics,
    telephonyProvider,
    sttProvider,
    llmProvider,
    ttsProvider,
  } = dependencies;

  return {
    config: Object.freeze(config),
    eventBus,
    logger,
    metrics,
    telephony: telephonyProvider,
    stt: sttProvider,
    llm: llmProvider,
    tts: ttsProvider,

    async readyStatus(): Promise<ReadyStatus> {
      const timestamp = Date.now();
      const checks = await Promise.allSettled([
        telephonyProvider.ping(),
        sttProvider.ping(),
        llmProvider.ping(),
        ttsProvider.ping(),
      ]);

      const providerNames = ['telephony', 'stt', 'llm', 'tts'] as const;
      const providers = checks.map((result, i) => ({
        providerName: providerNames[i],
        health:
          result.status === 'fulfilled'
            ? result.value
            : { status: 'unhealthy' as const, message: (result.reason as Error).message, checkedAt: timestamp },
        latencyMs: 0,
      }));

      const ready = providers.every((p) => p.health.status !== 'unhealthy');

      return { ready, providers, timestamp };
    },

    async shutdown(): Promise<void> {
      logger.info('VoiceEngine shutting down');
    },
  };
}

