export type AudioEncoding =
  | 'LINEAR16'
  | 'MULAW'
  | 'ALAW'
  | 'OPUS'
  | 'MP3'
  | 'OGG_OPUS';

export type AudioSampleRate = 8000 | 16000 | 22050 | 44100 | 48000;

export interface AudioFormat {
  readonly encoding: AudioEncoding;
  readonly sampleRate: AudioSampleRate;
  readonly channels: 1 | 2;
  readonly bitDepth?: 8 | 16 | 24 | 32;
}

export interface AudioChunk {
  readonly data: Buffer;
  readonly format: AudioFormat;
  readonly sequenceNumber: number;
  readonly durationMs: number;
}

export interface AudioProcessingConfig {
  readonly inputFormat: AudioFormat;
  readonly outputFormat: AudioFormat;
  readonly silenceThresholdMs: number;
  readonly maxChunkDurationMs: number;
}

import type { CallSid, SessionId } from '../types/index.js';

export type TransportProtocol = 'websocket' | 'webhook';
export type TransportState = 'connecting' | 'connected' | 'disconnecting' | 'disconnected';

export interface TransportMessage {
  readonly type: string;
  readonly payload: Readonly<Record<string, unknown>>;
}

export interface TransportConnectionConfig {
  readonly protocol: TransportProtocol;
  readonly host: string;
  readonly port: number;
  readonly path: string;
  readonly tlsEnabled: boolean;
  readonly timeoutMs: number;
  readonly maxReconnectAttempts: number;
  readonly reconnectBackoffMs: number;
}

export interface ITransport {
  readonly state: TransportState;
  readonly callSid: CallSid;
  readonly sessionId: SessionId;
  send(message: TransportMessage): Promise<void>;
  close(reason?: string): Promise<void>;
  onMessage(handler: (message: TransportMessage) => void): void;
  onClose(handler: (reason?: string) => void): void;
  onError(handler: (error: Error) => void): void;
}

/**
 * @module RuntimeEvents
 *
 * Strongly typed event definitions emitted by a `ConversationRuntime`.
 *
 * ## Ownership
 * Events are produced by `ConversationRuntime` and consumed by the surrounding
 * orchestration layer (call coordinator, monitoring, analytics). No module
 * inside the runtime consumes its own events.
 *
 * ## Thread Safety
 * Events are value objects — immutable once constructed. Safe to pass across
 * async boundaries without copying.
 *
 * ## Lifecycle
 * Events are emitted in strict chronological order within a single runtime
 * instance. Subscribers must not mutate the event payload.
 */

import type { Timestamp, SessionId, CallSid } from '../types/index.js';
import type { RuntimeState } from './RuntimeState.js';

/**
 * Common fields carried by every runtime event.
 */
interface BaseRuntimeEvent {
  /** Millisecond Unix timestamp of when the event was created. */
  readonly timestamp: Timestamp;
  /** The session this runtime is managing. */
  readonly sessionId: SessionId;
  /** The telephony call identifier bound to this runtime. */
  readonly callSid: CallSid;
}

/**
 * Emitted immediately after a `ConversationRuntime` instance is constructed
 * and enters the CREATED state.
 */
export interface RuntimeCreatedEvent extends BaseRuntimeEvent {
  readonly type: 'runtime.created';
  readonly campaignId: string;
}

/**
 * Emitted when the transport is fully established and the runtime enters
 * the CONNECTED state, ready to start the conversation.
 */
export interface RuntimeConnectedEvent extends BaseRuntimeEvent {
  readonly type: 'runtime.connected';
  readonly transportProtocol: string;
}

/**
 * Emitted each time the runtime enters the LISTENING state and begins
 * capturing caller audio via STT.
 */
export interface RuntimeListeningEvent extends BaseRuntimeEvent {
  readonly type: 'runtime.listening';
  /** Zero-based index of the current conversational turn. */
  readonly turnIndex: number;
}

/**
 * Emitted when the runtime enters the THINKING state.
 * The caller's utterance has been transcribed and the LLM request is in-flight.
 */
export interface RuntimeThinkingEvent extends BaseRuntimeEvent {
  readonly type: 'runtime.thinking';
  readonly turnIndex: number;
  /** The final transcript that triggered this thinking phase. */
  readonly transcript: string;
  /** Milliseconds elapsed from utterance end to LLM request dispatch. */
  readonly sttLatencyMs: number;
}

/**
 * Emitted when the runtime enters the SPEAKING state.
 * TTS audio is now streaming to the caller.
 */
export interface RuntimeSpeakingEvent extends BaseRuntimeEvent {
  readonly type: 'runtime.speaking';
  readonly turnIndex: number;
  /** Character count of the text being synthesised. */
  readonly textLength: number;
  /** The voice identifier used for synthesis. */
  readonly voice: string;
  /** Milliseconds elapsed from LLM response completion to TTS stream start. */
  readonly ttsLatencyMs: number;
}

/**
 * Emitted when the caller speaks while the runtime is in SPEAKING state,
 * triggering a barge-in and entering the INTERRUPTED state.
 */
export interface RuntimeInterruptedEvent extends BaseRuntimeEvent {
  readonly type: 'runtime.interrupted';
  readonly turnIndex: number;
  /** Milliseconds into the TTS stream at which the interruption occurred. */
  readonly interruptedAtMs: number;
}

/**
 * Emitted when the conversation ends gracefully and the runtime enters
 * the COMPLETED state.
 */
export interface RuntimeCompletedEvent extends BaseRuntimeEvent {
  readonly type: 'runtime.completed';
  /** Total number of completed conversational turns. */
  readonly totalTurns: number;
  /** Total wall-clock duration of the conversation in milliseconds. */
  readonly durationMs: number;
  /** Human-readable reason for completion (e.g. "goal_reached", "max_turns"). */
  readonly completionReason: string;
}

/**
 * Emitted when the runtime enters the CLOSED state and all resources
 * have been released.
 */
export interface RuntimeClosedEvent extends BaseRuntimeEvent {
  readonly type: 'runtime.closed';
  /** The state the runtime was in immediately before closing. */
  readonly closedFromState: RuntimeState;
}

/**
 * Emitted when the runtime encounters an unrecoverable error and enters
 * the FAILED state.
 */
export interface RuntimeErrorEvent extends BaseRuntimeEvent {
  readonly type: 'runtime.error';
  readonly errorCode: string;
  readonly errorMessage: string;
  /** The state the runtime occupied when the error occurred. */
  readonly failedInState: RuntimeState;
  /** Whether the error originated in a provider (STT/LLM/TTS/telephony). */
  readonly providerError: boolean;
}

/**
 * Discriminated union of all events emitted by a `ConversationRuntime`.
 */
export type RuntimeEvent =
  | RuntimeCreatedEvent
  | RuntimeConnectedEvent
  | RuntimeListeningEvent
  | RuntimeThinkingEvent
  | RuntimeSpeakingEvent
  | RuntimeInterruptedEvent
  | RuntimeCompletedEvent
  | RuntimeClosedEvent
  | RuntimeErrorEvent;

/** Maps each event type literal to its concrete event interface. */
export type RuntimeEventMap = {
  [E in RuntimeEvent as E['type']]: E;
};

export type RuntimeEventType = RuntimeEvent['type'];
export type RuntimeEventHandler<T extends RuntimeEvent = RuntimeEvent> = (event: T) => void;

/**
 * @module RuntimeTimers
 *
 * Timer interfaces used by a `ConversationRuntime` to enforce time-based
 * conversation policies without any concrete scheduling logic.
 *
 * ## Ownership
 * Timer instances are created and owned by the runtime factory.
 * The runtime holds references through these interfaces only — it never
 * owns or allocates OS-level timer resources directly.
 *
 * ## Thread Safety
 * All timer methods are intended to be called from the same async context
 * as the runtime. External cancellation is safe but must be followed by
 * a call to `reset()` or `cancel()` before the runtime transitions state.
 *
 * ## Lifecycle
 * Each timer is started, reset, and cancelled in strict coordination with
 * state transitions. A timer MUST be cancelled before `destroy()` is called
 * on the runtime.
 */

import type { Timestamp } from '../types/index.js';

/**
 * A cancellable, resettable one-shot or repeating timer handle.
 * Concrete implementations must not use `setTimeout` directly inside
 * the runtime layer — scheduling is owned by the factory/infrastructure.
 */
export interface TimerHandle {
  /** Whether this timer is currently active (started and not yet fired or cancelled). */
  readonly isActive: boolean;
  /** The UTC timestamp at which this timer was last started, or null if never started. */
  readonly startedAt: Timestamp | null;
  /** Cancels the timer. Safe to call even if the timer is not active. */
  cancel(): void;
  /** Resets the timer to its configured duration without changing the callback. */
  reset(): void;
}

/**
 * Monitors caller silence after the runtime enters LISTENING state.
 *
 * If the caller does not speak within `thresholdMs`, the runtime should
 * transition from LISTENING → WAITING so a re-engagement prompt can be sent.
 *
 * ## Lifecycle
 * - Started: on entry to LISTENING state.
 * - Reset: each time a non-silent audio chunk is received.
 * - Cancelled: on exit from LISTENING state (to THINKING or any terminal state).
 */
export interface SilenceTimer extends TimerHandle {
  /** Duration of silence in milliseconds that triggers the timeout callback. */
  readonly thresholdMs: number;
  /** Callback invoked when silence threshold is exceeded. */
  readonly onSilenceTimeout: () => void;
}

/**
 * Guards the maximum duration a TTS speech turn is allowed to run.
 *
 * If the TTS stream has not completed within `maxDurationMs`, the runtime
 * must abort the speech and transition to INTERRUPTED or COMPLETED.
 *
 * ## Lifecycle
 * - Started: on entry to SPEAKING state.
 * - Cancelled: when TTS stream completes normally, or when a barge-in occurs.
 */
export interface SpeechTimeoutTimer extends TimerHandle {
  /** Maximum milliseconds a single speech turn may last. */
  readonly maxDurationMs: number;
  /** Callback invoked when the speech timeout fires. */
  readonly onSpeechTimeout: () => void;
}

/**
 * Guards the maximum duration the LLM is allowed to produce a response.
 *
 * If the LLM has not completed within `maxDurationMs`, the runtime must
 * abort the LLM call, transition to FAILED or LISTENING with an error prompt.
 *
 * ## Lifecycle
 * - Started: on entry to THINKING state.
 * - Cancelled: when the LLM response is received or an error occurs.
 */
export interface ThinkingTimeoutTimer extends TimerHandle {
  /** Maximum milliseconds the LLM may take to return a complete response. */
  readonly maxDurationMs: number;
  /** Callback invoked when the thinking timeout fires. */
  readonly onThinkingTimeout: () => void;
}

/**
 * Enforces the maximum wall-clock duration for the entire conversation session.
 *
 * When this timer fires, the runtime must gracefully complete or forcibly close
 * the session, regardless of current state.
 *
 * ## Lifecycle
 * - Started: on entry to CONNECTED state.
 * - Cancelled: on entry to COMPLETED, FAILED, or CLOSED state.
 */
export interface SessionTimeoutTimer extends TimerHandle {
  /** Maximum session duration in milliseconds. */
  readonly maxDurationMs: number;
  /** Callback invoked when the session wall-clock timeout fires. */
  readonly onSessionTimeout: () => void;
}

/**
 * Sends periodic keep-alive signals over the transport to prevent proxy
 * or NAT timeouts from silently dropping the connection.
 *
 * ## Lifecycle
 * - Started: on entry to CONNECTED state.
 * - Cancelled: on exit from CONNECTED state or any terminal state.
 */
export interface HeartbeatTimer extends TimerHandle {
  /** Interval in milliseconds between heartbeat pulses. */
  readonly intervalMs: number;
  /** Callback invoked on each heartbeat tick. */
  readonly onHeartbeat: () => void;
}

/**
 * Aggregated container of all timers managed by a single runtime instance.
 */
export interface RuntimeTimers {
  readonly silence: SilenceTimer;
  readonly speech: SpeechTimeoutTimer;
  readonly thinking: ThinkingTimeoutTimer;
  readonly session: SessionTimeoutTimer;
  readonly heartbeat: HeartbeatTimer;
}

/**
 * @module RuntimeContext
 *
 * The immutable dependency bag passed to every component that participates
 * in a single live conversation.
 *
 * ## Ownership
 * Created once by `RuntimeFactory.createConversationRuntime()` and passed
 * by reference to the runtime. The context object itself is frozen after
 * construction; nothing may add or replace its fields at runtime.
 *
 * ## Thread Safety
 * `RuntimeContext` is read-only after creation. All fields are either
 * value types or interfaces whose implementations must be individually
 * thread-safe.
 *
 * ## Lifecycle
 * The context outlives no runtime. When `destroy()` is called on the
 * runtime, the context reference is released and must not be used again.
 */

import type { VoiceEngineConfig } from '../config/index.js';
import type { ILogger } from '../logger/index.js';
import type { IMetricsCollector } from '../metrics/index.js';
import type { ProviderRegistry } from '../providers/index.js';
import type { VoiceSession, CampaignSnapshot } from '../session/index.js';
import type { Timestamp, SessionId, CallSid } from '../types/index.js';

/**
 * A monotonic clock interface that abstracts wall-clock access.
 * Implementations may be replaced in test environments with a controlled clock.
 */
export interface IClock {
  /**
   * Returns the current time as a millisecond Unix timestamp.
   * Must be monotonically non-decreasing within a single runtime instance.
   */
  now(): Timestamp;
}

/**
 * A point-in-time snapshot of the AI knowledge base associated with the
 * campaign. Frozen at session creation; never mutated during a live call.
 */
export interface KnowledgeSnapshot {
  /** Unique identifier for this knowledge snapshot version. */
  readonly snapshotId: string;
  /** The campaign this knowledge belongs to. */
  readonly campaignId: string;
  /** Ordered list of knowledge document excerpts available to the LLM. */
  readonly documents: readonly KnowledgeDocument[];
  /** UTC timestamp when this snapshot was captured. */
  readonly capturedAt: Timestamp;
}

/**
 * A single document or excerpt within the knowledge base snapshot.
 */
export interface KnowledgeDocument {
  /** Unique document identifier. */
  readonly documentId: string;
  /** Human-readable document title. */
  readonly title: string;
  /** Plain-text content made available to the LLM system prompt. */
  readonly content: string;
  /** MIME type of the original source document. */
  readonly mimeType: string;
}

/**
 * The complete, immutable dependency context for one `ConversationRuntime`
 * instance.
 *
 * Every dependency required to run a live conversation is declared here.
 * No runtime component may reach outside this context for its dependencies.
 */
export interface RuntimeContext {
  /**
   * The live session state object for this conversation.
   * The runtime reads session state through this reference; it does not
   * own the session persistence layer.
   */
  readonly session: VoiceSession;

  /**
   * A frozen copy of the voice engine configuration active when the
   * runtime was created. Configuration does not change mid-call.
   */
  readonly config: Readonly<VoiceEngineConfig>;

  /**
   * Structured logger scoped to this specific runtime instance.
   * Always contains `sessionId` and `callSid` as bound fields.
   */
  readonly logger: ILogger;

  /**
   * Metrics collector for emitting per-turn and per-call measurements.
   */
  readonly metrics: IMetricsCollector;

  /**
   * Provider factory registry from which telephony, STT, LLM, and TTS
   * provider instances are resolved.
   */
  readonly providers: ProviderRegistry;

  /**
   * Frozen snapshot of the AI knowledge base associated with this campaign.
   * Captured once at session start; never refreshed mid-call.
   */
  readonly knowledge: KnowledgeSnapshot;

  /**
   * Frozen snapshot of the campaign configuration (script, voice, calling
   * hours) as it existed when the call was initiated.
   */
  readonly campaign: CampaignSnapshot;

  /**
   * Monotonic clock used by the runtime and timers.
   * Must never be replaced after context construction.
   */
  readonly clock: IClock;

  /**
   * Convenience accessor — identical to `session.serializable.sessionId`.
   */
  readonly sessionId: SessionId;

  /**
   * Convenience accessor — identical to `session.serializable.callSid`.
   */
  readonly callSid: CallSid;
}

/**
 * @module RuntimeFactory
 *
 * Dependency injection factory for constructing `ConversationRuntime` instances.
 *
 * ## Purpose
 * Centralises all wiring of runtime dependencies. No caller outside this
 * module needs to know which concrete types implement the runtime interfaces.
 *
 * ## Ownership
 * The factory is a singleton owned by the application bootstrap layer.
 * It does not hold any per-call state — it is safe to reuse across calls.
 *
 * ## Thread Safety
 * `createConversationRuntime()` is stateless and reentrant. Concurrent calls
 * each produce an independent runtime instance with no shared mutable state.
 *
 * ## Lifecycle
 * The factory itself has no lifecycle. Individual runtimes it produces are
 * independently managed by their owners.
 */

import type { ConversationRuntime } from './ConversationRuntime.js';
import type { RuntimeContext } from './RuntimeContext.js';
import type { RuntimeTimers } from './RuntimeTimers.js';
import type { RuntimeEventHandler, RuntimeEvent } from './RuntimeEvents.js';

/**
 * Configuration supplied to the factory when constructing a new runtime.
 * All fields are required; the factory performs no defaulting.
 */
export interface RuntimeCreationOptions {
  /**
   * The fully assembled dependency context for this conversation.
   * Must be frozen before being passed to the factory.
   */
  readonly context: RuntimeContext;

  /**
   * Pre-configured timer handles for this runtime instance.
   * The factory does not create timers; the caller provides them
   * so scheduling infrastructure remains outside the runtime.
   */
  readonly timers: RuntimeTimers;

  /**
   * Optional subscriber to all runtime lifecycle events.
   * If provided, it will be registered before the runtime is returned
   * so no events are lost.
   */
  readonly onEvent?: RuntimeEventHandler<RuntimeEvent>;
}

/**
 * The factory interface for producing `ConversationRuntime` instances.
 *
 * Implementations must be stateless — all per-call state lives inside
 * the runtime instance, not the factory.
 */
export interface IRuntimeFactory {
  /**
   * Constructs and returns a new `ConversationRuntime` in the CREATED state.
   *
   * The returned runtime has not yet been initialised. The caller must invoke
   * `initialize()` followed by `connect()` before audio processing can begin.
   *
   * @param options - Wired dependencies for this conversation.
   * @returns A new runtime instance in the CREATED state.
   * @throws {ConfigurationError} if required fields in `options.context` are missing.
   */
  createConversationRuntime(options: RuntimeCreationOptions): ConversationRuntime;
}

/**
 * Creates and returns a new `ConversationRuntime` using the provided options.
 *
 * This is the single public entry point for runtime construction. It delegates
 * to the registered `IRuntimeFactory` implementation.
 *
 * @param factory - The factory implementation to delegate to.
 * @param options - Runtime creation options including context and timers.
 * @returns A new `ConversationRuntime` in the CREATED state.
 *
 * @example
 * ```typescript
 * const runtime = createConversationRuntime(factory, {
 *   context,
