/**
 * @module EnvironmentLoader
 *
 * The sole authorised point of contact with `process.env`.
 *
 * ## Purpose
 * Reads raw environment variables and converts them into a strongly typed,
 * validated intermediate object. No caller outside this module may read
 * `process.env` directly.
 *
 * ## Ownership
 * Created once during bootstrap. Immutable after construction.
 *
 * ## Thread Safety
 * `process.env` is read exactly once at construction time. All subsequent
 * accesses go through the frozen result object.
 *
 * ## Fail-Fast
 * Missing or malformed required variables throw a `ConfigurationError`
 * immediately at load time, before any provider is initialised.
 */

import { z } from 'zod';
import { ConfigurationError } from '../errors/index.js';

const RawEnvSchema = z.object({
  NODE_ENV: z.enum(['development', 'test', 'production']).default('development'),

  VOICE_ENGINE_LOG_LEVEL: z.enum(['debug', 'info', 'warn', 'error']).default('info'),
  VOICE_ENGINE_PRETTY_LOGS: z
    .string()
    .optional()
    .transform((v) => v === 'true'),

  VOICE_ENGINE_METRICS_ENABLED: z
    .string()
    .optional()
    .transform((v) => v !== 'false'),
  VOICE_ENGINE_METRICS_PREFIX: z.string().default('nijvox_voice_'),
  VOICE_ENGINE_METRICS_FLUSH_MS: z
    .string()
    .optional()
    .transform((v) => (v ? parseInt(v, 10) : 10_000))
    .pipe(z.number().int().positive()),

  VOICE_ENGINE_SESSION_TTL_SECONDS: z
    .string()
    .optional()
    .transform((v) => (v ? parseInt(v, 10) : 3600))
    .pipe(z.number().int().positive()),
  VOICE_ENGINE_MAX_SESSIONS: z
    .string()
    .optional()
    .transform((v) => (v ? parseInt(v, 10) : 100))
    .pipe(z.number().int().positive()),
  VOICE_ENGINE_SESSION_STORE: z.enum(['memory', 'redis']).default('memory'),
  VOICE_ENGINE_REDIS_URL: z.string().url().optional(),

  VOICE_ENGINE_TRANSPORT_PROTOCOL: z.enum(['websocket', 'webhook']).default('websocket'),
  VOICE_ENGINE_TRANSPORT_HOST: z.string().default('0.0.0.0'),
  VOICE_ENGINE_TRANSPORT_PORT: z
    .string()
    .optional()
    .transform((v) => (v ? parseInt(v, 10) : 8080))
    .pipe(z.number().int().min(1).max(65535)),
  VOICE_ENGINE_TRANSPORT_PATH: z.string().default('/voice-engine/ws'),
  VOICE_ENGINE_TRANSPORT_TLS: z
    .string()
    .optional()
    .transform((v) => v === 'true'),
  VOICE_ENGINE_TRANSPORT_TIMEOUT_MS: z
    .string()
    .optional()
    .transform((v) => (v ? parseInt(v, 10) : 30_000))
    .pipe(z.number().int().positive()),

  VOICE_ENGINE_HEALTH_PING_INTERVAL_MS: z
    .string()
    .optional()
    .transform((v) => (v ? parseInt(v, 10) : 30_000))
    .pipe(z.number().int().positive()),
  VOICE_ENGINE_HEALTH_PING_TIMEOUT_MS: z
    .string()
    .optional()
    .transform((v) => (v ? parseInt(v, 10) : 5_000))
    .pipe(z.number().int().positive()),

  VOICE_ENGINE_MAX_CALL_DURATION_SECONDS: z
    .string()
    .optional()
    .transform((v) => (v ? parseInt(v, 10) : 1800))
    .pipe(z.number().int().positive()),
  VOICE_ENGINE_VALIDATE_WEBHOOK_SIG: z
    .string()
    .optional()
    .transform((v) => v !== 'false'),
  VOICE_ENGINE_WEBHOOK_SECRET: z.string().optional(),

  TELEPHONY_PROVIDER: z.string().default('exotel'),
  TELEPHONY_API_KEY: z.string().default(''),
  TELEPHONY_API_SECRET: z.string().optional(),
  TELEPHONY_ACCOUNT_SID: z.string().optional(),
  TELEPHONY_BASE_URL: z.string().url().default('https://api.exotel.com'),
  TELEPHONY_TIMEOUT_MS: z
    .string()
    .optional()
    .transform((v) => (v ? parseInt(v, 10) : 10_000))
    .pipe(z.number().int().positive()),

  STT_PROVIDER: z.string().default('google'),
  STT_API_KEY: z.string().default(''),
  STT_MODEL: z.string().default('default'),
  STT_LANGUAGE: z.string().default('en-US'),
  STT_TIMEOUT_MS: z
    .string()
    .optional()
    .transform((v) => (v ? parseInt(v, 10) : 5_000))
    .pipe(z.number().int().positive()),

  LLM_PROVIDER: z.string().default('openai'),
  LLM_API_KEY: z.string().default(''),
  LLM_MODEL: z.string().default('gpt-4o'),
  LLM_MAX_TOKENS: z
    .string()
    .optional()
    .transform((v) => (v ? parseInt(v, 10) : 512))
    .pipe(z.number().int().positive()),
  LLM_TEMPERATURE: z
    .string()
    .optional()
    .transform((v) => (v ? parseFloat(v) : 0.7))
    .pipe(z.number().min(0).max(2)),
  LLM_TIMEOUT_MS: z
    .string()
    .optional()
    .transform((v) => (v ? parseInt(v, 10) : 15_000))
    .pipe(z.number().int().positive()),

  TTS_PROVIDER: z.string().default('openai'),
  TTS_API_KEY: z.string().default(''),
  TTS_DEFAULT_VOICE: z.string().default('alloy'),
  TTS_TIMEOUT_MS: z
    .string()
    .optional()
    .transform((v) => (v ? parseInt(v, 10) : 8_000))
    .pipe(z.number().int().positive()),
});

export type RawEnv = z.infer<typeof RawEnvSchema>;

/**
 * The fully typed, validated representation of all environment variables
 * consumed by the Voice Engine.
 */
export interface LoadedEnvironment {
  readonly nodeEnv: 'development' | 'test' | 'production';
  readonly logging: {
    readonly level: 'debug' | 'info' | 'warn' | 'error';
    readonly prettyPrint: boolean;
  };
  readonly metrics: {
    readonly enabled: boolean;
    readonly prefix: string;
    readonly flushIntervalMs: number;
  };
  readonly session: {
    readonly ttlSeconds: number;
    readonly maxConcurrentSessions: number;
    readonly storeType: 'memory' | 'redis';
    readonly redisUrl?: string;
  };
  readonly transport: {
    readonly protocol: 'websocket' | 'webhook';
    readonly host: string;
    readonly port: number;
    readonly path: string;
    readonly tlsEnabled: boolean;
    readonly timeoutMs: number;
  };
  readonly health: {
    readonly pingIntervalMs: number;
    readonly pingTimeoutMs: number;
  };
  readonly security: {
    readonly maxCallDurationSeconds: number;
    readonly validateWebhookSignature: boolean;
    readonly webhookSecret?: string;
  };
  readonly providers: {
    readonly telephony: {
      readonly provider: string;
      readonly apiKey: string;
      readonly apiSecret?: string;
      readonly accountSid?: string;
      readonly baseUrl: string;
      readonly timeoutMs: number;
    };
    readonly stt: {
      readonly provider: string;
      readonly apiKey: string;
      readonly model: string;
      readonly languageCode: string;
      readonly timeoutMs: number;
    };
    readonly llm: {
      readonly provider: string;
      readonly apiKey: string;
      readonly model: string;
      readonly maxTokens: number;
      readonly temperature: number;
      readonly timeoutMs: number;
    };
    readonly tts: {
      readonly provider: string;
      readonly apiKey: string;
      readonly defaultVoice: string;
      readonly timeoutMs: number;
    };
  };
}

/**
 * Reads and validates all Voice Engine environment variables exactly once.
 *
 * @throws {ConfigurationError} if any required variable is missing or invalid.
 */
export function loadEnvironment(): LoadedEnvironment {
  const result = RawEnvSchema.safeParse(process.env);

  if (!result.success) {
    const issues = result.error.issues
      .map((i) => `  ${i.path.join('.')}: ${i.message}`)
      .join('\n');
    throw new ConfigurationError(
      `Voice Engine environment validation failed:\n${issues}`,
      { issues: result.error.issues }
    );
  }

  const e = result.data;

  return Object.freeze({
    nodeEnv: e.NODE_ENV,
    logging: Object.freeze({
      level: e.VOICE_ENGINE_LOG_LEVEL,
      prettyPrint: e.VOICE_ENGINE_PRETTY_LOGS,
    }),
    metrics: Object.freeze({
      enabled: e.VOICE_ENGINE_METRICS_ENABLED,
      prefix: e.VOICE_ENGINE_METRICS_PREFIX,
      flushIntervalMs: e.VOICE_ENGINE_METRICS_FLUSH_MS,
    }),
    session: Object.freeze({
      ttlSeconds: e.VOICE_ENGINE_SESSION_TTL_SECONDS,
      maxConcurrentSessions: e.VOICE_ENGINE_MAX_SESSIONS,
      storeType: e.VOICE_ENGINE_SESSION_STORE,
      redisUrl: e.VOICE_ENGINE_REDIS_URL,
    }),
    transport: Object.freeze({
      protocol: e.VOICE_ENGINE_TRANSPORT_PROTOCOL,
      host: e.VOICE_ENGINE_TRANSPORT_HOST,
      port: e.VOICE_ENGINE_TRANSPORT_PORT,
      path: e.VOICE_ENGINE_TRANSPORT_PATH,
      tlsEnabled: e.VOICE_ENGINE_TRANSPORT_TLS,
      timeoutMs: e.VOICE_ENGINE_TRANSPORT_TIMEOUT_MS,
    }),
    health: Object.freeze({
      pingIntervalMs: e.VOICE_ENGINE_HEALTH_PING_INTERVAL_MS,
      pingTimeoutMs: e.VOICE_ENGINE_HEALTH_PING_TIMEOUT_MS,
    }),
    security: Object.freeze({
      maxCallDurationSeconds: e.VOICE_ENGINE_MAX_CALL_DURATION_SECONDS,
      validateWebhookSignature: e.VOICE_ENGINE_VALIDATE_WEBHOOK_SIG,
      webhookSecret: e.VOICE_ENGINE_WEBHOOK_SECRET,
    }),
    providers: Object.freeze({
      telephony: Object.freeze({
        provider: e.TELEPHONY_PROVIDER,
        apiKey: e.TELEPHONY_API_KEY,
        apiSecret: e.TELEPHONY_API_SECRET,
        accountSid: e.TELEPHONY_ACCOUNT_SID,
        baseUrl: e.TELEPHONY_BASE_URL,
        timeoutMs: e.TELEPHONY_TIMEOUT_MS,
      }),
      stt: Object.freeze({
        provider: e.STT_PROVIDER,
        apiKey: e.STT_API_KEY,
        model: e.STT_MODEL,
        languageCode: e.STT_LANGUAGE,
        timeoutMs: e.STT_TIMEOUT_MS,
      }),
      llm: Object.freeze({
        provider: e.LLM_PROVIDER,
        apiKey: e.LLM_API_KEY,
        model: e.LLM_MODEL,
        maxTokens: e.LLM_MAX_TOKENS,
        temperature: e.LLM_TEMPERATURE,
        timeoutMs: e.LLM_TIMEOUT_MS,
      }),
      tts: Object.freeze({
        provider: e.TTS_PROVIDER,
        apiKey: e.TTS_API_KEY,
        defaultVoice: e.TTS_DEFAULT_VOICE,
        timeoutMs: e.TTS_TIMEOUT_MS,
      }),
    }),
  }) satisfies LoadedEnvironment;
}

/**
 * @module ConfigLoader
 *
 * Merges environment variables, built-in defaults, and optional runtime
 * overrides into a single frozen `VoiceEngineConfig`.
 *
 * ## Purpose
 * Produces the authoritative, immutable configuration object consumed by
 * every Voice Engine component. Validation is performed via the existing
 * Zod schemas from the foundation layer.
 *
 * ## Ownership
 * Called once during bootstrap by `Bootstrap.ts`. The resulting config is
 * passed into the DI container and never mutated.
 *
 * ## Fail-Fast
 * Throws `ConfigurationError` if the merged configuration fails Zod validation.
 */

import { VoiceEngineConfigSchema } from '../config/index.js';
import type { VoiceEngineConfig } from '../config/index.js';
import { ConfigurationError } from '../errors/index.js';
import type { LoadedEnvironment } from './EnvironmentLoader.js';

/** Partial overrides supplied programmatically at bootstrap time. */
export type ConfigOverrides = Partial<{
  logging: Partial<VoiceEngineConfig['logging']>;
  metrics: Partial<VoiceEngineConfig['metrics']>;
  session: Partial<VoiceEngineConfig['session']>;
  transport: Partial<VoiceEngineConfig['transport']>;
  health: Partial<VoiceEngineConfig['health']>;
  security: Partial<VoiceEngineConfig['security']>;
}>;

/**
 * Merges a `LoadedEnvironment` with optional programmatic overrides and
 * produces a fully validated, deeply frozen `VoiceEngineConfig`.
 *
 * Priority (highest → lowest):
 *   1. `overrides` (programmatic, e.g. test fixtures)
 *   2. `env` (environment variables)
 *   3. Schema defaults (declared in `VoiceEngineConfigSchema`)
 *
 * @throws {ConfigurationError} if the merged config fails schema validation.
 */
export function loadConfig(
  env: LoadedEnvironment,
  overrides: ConfigOverrides = {}
): Readonly<VoiceEngineConfig> {
  const merged = {
    providers: {
      telephony: {
        provider: env.providers.telephony.provider,
        apiKey: env.providers.telephony.apiKey,
        apiSecret: env.providers.telephony.apiSecret,
        accountSid: env.providers.telephony.accountSid,
        baseUrl: env.providers.telephony.baseUrl,
        timeoutMs: env.providers.telephony.timeoutMs,
      },
      stt: {
        provider: env.providers.stt.provider,
        apiKey: env.providers.stt.apiKey,
        model: env.providers.stt.model,
        languageCode: env.providers.stt.languageCode,
        timeoutMs: env.providers.stt.timeoutMs,
      },
      llm: {
        provider: env.providers.llm.provider,
        apiKey: env.providers.llm.apiKey,
        model: env.providers.llm.model,
        maxTokens: env.providers.llm.maxTokens,
        temperature: env.providers.llm.temperature,
        timeoutMs: env.providers.llm.timeoutMs,
      },
      tts: {
        provider: env.providers.tts.provider,
        apiKey: env.providers.tts.apiKey,
        defaultVoice: env.providers.tts.defaultVoice,
        timeoutMs: env.providers.tts.timeoutMs,
      },
    },
    logging: {
      level: env.logging.level,
      prettyPrint: env.logging.prettyPrint,
      ...overrides.logging,
    },
    metrics: {
      enabled: env.metrics.enabled,
      prefix: env.metrics.prefix,
      flushIntervalMs: env.metrics.flushIntervalMs,
      ...overrides.metrics,
    },
    session: {
      ttlSeconds: env.session.ttlSeconds,
      maxConcurrentSessions: env.session.maxConcurrentSessions,
      storeType: env.session.storeType,
      redisUrl: env.session.redisUrl,
      ...overrides.session,
    },
    transport: {
      protocol: env.transport.protocol,
      host: env.transport.host,
      port: env.transport.port,
      path: env.transport.path,
      tlsEnabled: env.transport.tlsEnabled,
      timeoutMs: env.transport.timeoutMs,
      maxReconnectAttempts: 3,
      reconnectBackoffMs: 1_000,
      ...overrides.transport,
    },
    health: {
      pingIntervalMs: env.health.pingIntervalMs,
      pingTimeoutMs: env.health.pingTimeoutMs,
      unhealthyThreshold: 3,
      healthyThreshold: 1,
      ...overrides.health,
    },
    security: {
      allowedCallerIds: [],
      maxCallDurationSeconds: env.security.maxCallDurationSeconds,
      validateWebhookSignature: env.security.validateWebhookSignature,
      webhookSecret: env.security.webhookSecret,
      ...overrides.security,
    },
  };

  const result = VoiceEngineConfigSchema.safeParse(merged);

  if (!result.success) {
    const issues = result.error.issues
      .map((i) => `  ${i.path.join('.')}: ${i.message}`)
      .join('\n');
    throw new ConfigurationError(
      `Voice Engine config validation failed:\n${issues}`,
      { issues: result.error.issues }
    );
  }

  return deepFreeze(result.data) as Readonly<VoiceEngineConfig>;
}

function deepFreeze<T>(obj: T): T {
  if (obj === null || typeof obj !== 'object') return obj;
  Object.freeze(obj);
  for (const key of Object.keys(obj as object)) {
    const val = (obj as Record<string, unknown>)[key];
    if (val !== null && typeof val === 'object' && !Object.isFrozen(val)) {
      deepFreeze(val);
    }
  }
  return obj;
}

/**
 * @module DependencyContainer
 *
 * A lightweight, type-safe dependency injection container with no external
 * library dependencies.
 *
 * ## Purpose
 * Centralises service registration and resolution. Supports singleton
 * instances, lazy factory functions, and pre-constructed instances.
 *
 * ## Ownership
 * One container is created per Voice Engine runtime. It is owned by
 * `Bootstrap.ts` and passed (read-only) to modules that need resolution.
 *
 * ## Thread Safety
 * Registration must complete before any concurrent resolution begins.
 * After the bootstrap phase, the container is considered sealed.
 * `resolve()` is safe to call concurrently once sealed.
 *
 * ## Lifecycle
 * 1. Bootstrap registers all services.
 * 2. Container is sealed (no further registration).
 * 3. Components resolve dependencies during initialisation.
 * 4. `clear()` is called on shutdown to release references.
 */

import { ConfigurationError } from '../errors/index.js';
import { ErrorCode } from '../errors/index.js';

/** The type of registration stored for each token. */
type RegistrationKind = 'singleton' | 'factory' | 'instance';

interface Registration<T> {
  readonly kind: RegistrationKind;
  readonly factory?: () => T;
  instance?: T;
  readonly readonly: boolean;
}

/**
 * An opaque token used to identify a registered service.
 * Use `token<T>(name)` to create typed tokens.
 */
export interface Token<T> {
  readonly _type: T;
  readonly name: string;
}

/**
 * Creates a typed DI token with the given human-readable name.
 *
 * @example
 * ```typescript
 * const LOGGER_TOKEN = token<ILogger>('ILogger');
 * container.registerInstance(LOGGER_TOKEN, myLogger);
 * const logger = container.resolve(LOGGER_TOKEN);
 * ```
 */
export function token<T>(name: string): Token<T> {
  return { name } as Token<T>;
}

/**
 * A lightweight dependency injection container.
 *
 * Supports singleton (lazy), factory (called fresh on each resolve), and
 * pre-constructed instance registrations.
 */
export class DependencyContainer {
  private readonly _registry = new Map<string, Registration<unknown>>();
  private _sealed = false;

  /**
   * Registers a singleton: the factory is called at most once, and the
   * result is cached for all subsequent `resolve()` calls.
   *
   * @throws {ConfigurationError} if the token is already registered as readonly.
   */
  registerSingleton<T>(tok: Token<T>, factory: () => T): this {
    this._assertWritable(tok.name);
    this._registry.set(tok.name, { kind: 'singleton', factory, readonly: false });
    return this;
  }

  /**
   * Registers a factory: the factory is called on every `resolve()` call.
   * No caching occurs.
   *
   * @throws {ConfigurationError} if the token is already registered as readonly.
   */
  registerFactory<T>(tok: Token<T>, factory: () => T): this {
    this._assertWritable(tok.name);
    this._registry.set(tok.name, { kind: 'factory', factory, readonly: false });
    return this;
  }

  /**
   * Registers a pre-constructed instance. The instance is returned directly
   * on every `resolve()` call.
   *
   * @param readonly_ - If true, the registration cannot be overwritten.
   * @throws {ConfigurationError} if the token is already registered as readonly.
   */
  registerInstance<T>(tok: Token<T>, instance: T, readonly_: boolean = false): this {
    this._assertWritable(tok.name);
    this._registry.set(tok.name, { kind: 'instance', instance, readonly: readonly_ });
    return this;
  }

  /**
   * Resolves a registered token to its value.
   *
   * @throws {ConfigurationError} if the token has not been registered.
   */
  resolve<T>(tok: Token<T>): T {
    const reg = this._registry.get(tok.name) as Registration<T> | undefined;
    if (!reg) {
      throw new ConfigurationError(`DependencyContainer: token "${tok.name}" is not registered.`);
    }

    if (reg.kind === 'instance') {
      return reg.instance as T;
    }

    if (reg.kind === 'factory') {
      return reg.factory!() as T;
    }

    if (reg.kind === 'singleton') {
      if (reg.instance === undefined) {
        (reg as Registration<T>).instance = reg.factory!() as T;
      }
      return reg.instance as T;
    }

    throw new ConfigurationError(
      `DependencyContainer: unknown registration kind for "${tok.name}".`,
      { kind: (reg as { kind: string }).kind }
    );
  }

  /**
   * Returns true if the given token has a registration.
   */
  has<T>(tok: Token<T>): boolean {
    return this._registry.has(tok.name);
  }

  /**
   * Removes all registrations. Intended for use during shutdown or in tests.
   */
  clear(): void {
    this._sealed = false;
    this._registry.clear();
  }

  /**
   * Seals the container. After sealing, no new registrations are permitted.
   */
  seal(): void {
    this._sealed = true;
  }

  /** Whether the container has been sealed against further registration. */
  get isSealed(): boolean {
    return this._sealed;
  }

  private _assertWritable(name: string): void {
    if (this._sealed) {
      throw new ConfigurationError(
        `DependencyContainer: container is sealed; cannot register "${name}".`
      );
    }
    const existing = this._registry.get(name);
    if (existing?.readonly) {
      throw new ConfigurationError(
        `DependencyContainer: token "${name}" is marked readonly and cannot be overwritten.`
      );
    }
  }
}

/**
 * @module ProviderResolver
 *
 * Resolves registered provider instances from the DI container by role.
 *
 * ## Purpose
 * Provides a named, role-based lookup of provider implementations.
 * This module contains NO provider logic — it only reads from the container.
 *
 * ## Ownership
 * Created by `Bootstrap.ts`. Passed to `RuntimeContext` as the
 * `ProviderRegistry` interface.
 *
 * ## Thread Safety
 * Stateless after construction. Safe to share across concurrent runtimes.
 *
 * ## Lifecycle
 * Valid for the lifetime of the DI container. Becomes invalid after
 * `container.clear()` is called.
 */

import type { DependencyContainer } from './DependencyContainer.js';
import type { Token } from './DependencyContainer.js';
import type {
  ITelephonyProvider,
  ISTTProvider,
  ILLMProvider,
  ITTSProvider,
} from '../interfaces/index.js';
import type { ILogger } from '../logger/index.js';
import type { IMetricsCollector } from '../metrics/index.js';
import type { HealthRegistry } from './HealthRegistry.js';

/** All DI tokens used by the Voice Engine provider resolver. */
export const Tokens = {
  TELEPHONY_PROVIDER: { name: 'ITelephonyProvider' } as Token<ITelephonyProvider>,
  STT_PROVIDER:       { name: 'ISTTProvider' }       as Token<ISTTProvider>,
  LLM_PROVIDER:       { name: 'ILLMProvider' }       as Token<ILLMProvider>,
  TTS_PROVIDER:       { name: 'ITTSProvider' }       as Token<ITTSProvider>,
  LOGGER:             { name: 'ILogger' }            as Token<ILogger>,
  METRICS:            { name: 'IMetricsCollector' }  as Token<IMetricsCollector>,
  HEALTH_REGISTRY:    { name: 'HealthRegistry' }     as Token<HealthRegistry>,
} as const;

/**
 * Resolves provider instances from the DI container by semantic role.
 *
 * Consumers should depend on this interface rather than the concrete
 * `ProviderResolver` class.
 */
export interface IProviderResolver {
  /** Returns the registered telephony provider. */
  telephony(): ITelephonyProvider;
  /** Returns the registered STT provider. */
  stt(): ISTTProvider;
  /** Returns the registered LLM provider. */
  llm(): ILLMProvider;
  /** Returns the registered TTS provider. */
  tts(): ITTSProvider;
  /** Returns the registered logger. */
  logger(): ILogger;
  /** Returns the registered metrics collector. */
  metrics(): IMetricsCollector;
  /** Returns the health registry. */
  health(): HealthRegistry;
}

/**
 * Concrete resolver that reads provider instances from a `DependencyContainer`.
 */
export class ProviderResolver implements IProviderResolver {
  private readonly _container: DependencyContainer;

  constructor(container: DependencyContainer) {
    this._container = container;
  }

  telephony(): ITelephonyProvider {
    return this._container.resolve(Tokens.TELEPHONY_PROVIDER);
  }

  stt(): ISTTProvider {
    return this._container.resolve(Tokens.STT_PROVIDER);
  }

  llm(): ILLMProvider {
    return this._container.resolve(Tokens.LLM_PROVIDER);
  }

  tts(): ITTSProvider {
    return this._container.resolve(Tokens.TTS_PROVIDER);
  }

  logger(): ILogger {
    return this._container.resolve(Tokens.LOGGER);
  }

  metrics(): IMetricsCollector {
    return this._container.resolve(Tokens.METRICS);
  }

  health(): HealthRegistry {
    return this._container.resolve(Tokens.HEALTH_REGISTRY);
  }
}

/**
 * @module HealthRegistry
 *
 * Tracks health-check callbacks for all registered Voice Engine providers
 * and aggregates them into a single `ReadyStatus`.
 *
 * ## Purpose
 * Any component (provider, transport, session store) that exposes a health
 * check registers itself here. The registry aggregates and exposes the
 * collective health of the Voice Engine without owning any provider logic.
 *
 * ## Ownership
 * Owned by the bootstrap container. There is one registry per Voice Engine
 * runtime instance.
 *
 * ## Thread Safety
 * `register()` and `unregister()` must be called during bootstrap before
 * any concurrent `getHealth()` calls begin. `getHealth()` and `getReadyStatus()`
 * are safe to call concurrently once the registry is sealed.
 *
 * ## Lifecycle
 * 1. Bootstrap registers all provider health callbacks.
 * 2. Monitoring layer calls `getReadyStatus()` periodically.
 * 3. On shutdown, providers call `unregister()`.
 */

import type { HealthStatus, ProviderHealth, ReadyStatus } from '../monitoring/index.js';

/**
 * A callback that asynchronously returns the current health of a provider.
 */
export type HealthCallback = () => Promise<HealthStatus>;

/**
 * A registered health entry in the registry.
 */
interface HealthEntry {
  readonly providerName: string;
  readonly callback: HealthCallback;
}

/**
 * Manages health-check registrations and aggregates provider health.
 */
export class HealthRegistry {
  private readonly _entries = new Map<string, HealthEntry>();

  /**
   * Registers a health-check callback for the named provider.
   * If a registration already exists for this name, it is replaced.
   *
   * @param providerName - Unique identifier for the provider (e.g. "openai-llm").
   * @param callback - Async function returning the current `HealthStatus`.
   */
  register(providerName: string, callback: HealthCallback): void {
    this._entries.set(providerName, { providerName, callback });
  }

  /**
   * Removes the health-check registration for the named provider.
   * Safe to call even if the provider was never registered.
   */
  unregister(providerName: string): void {
    this._entries.delete(providerName);
  }

  /**
   * Invokes the health callback for a single named provider.
   *
   * @returns `ProviderHealth` for the named provider.
   * @throws {Error} if no provider with that name is registered.
   */
  async getHealth(providerName: string): Promise<ProviderHealth> {
    const entry = this._entries.get(providerName);
    if (!entry) {
      throw new Error(
        `HealthRegistry: no provider registered with name "${providerName}".`
      );
    }

    const startMs = Date.now();
    let health: HealthStatus;

    try {
      health = await entry.callback();
    } catch (err) {
      health = {
        status: 'unhealthy',
        message: err instanceof Error ? err.message : String(err),
        checkedAt: Date.now(),
      };
    }

    return {
      providerName,
      health,
      latencyMs: Date.now() - startMs,
    };
  }

  /**
   * Invokes all registered health callbacks in parallel and aggregates
   * the results into a `ReadyStatus`.
   *
   * The engine is considered ready only if every registered provider
   * reports a status of `"healthy"` or `"degraded"`.
   */
  async getReadyStatus(): Promise<ReadyStatus> {
    const timestamp = Date.now();
    const names = Array.from(this._entries.keys());

    const results = await Promise.allSettled(
      names.map((name) => this.getHealth(name))
    );

    const providers: ProviderHealth[] = results.map((result, i) => {
      if (result.status === 'fulfilled') {
        return result.value;
      }
      return {
        providerName: names[i],
        health: {
          status: 'unhealthy' as const,
          message: result.reason instanceof Error
            ? result.reason.message
            : String(result.reason),
          checkedAt: timestamp,
        },
        latencyMs: 0,
      };
    });

    const ready = providers.every((p) => p.health.status !== 'unhealthy');

    return { ready, providers, timestamp };
  }

  /** Returns the number of registered health callbacks. */
  get size(): number {
    return this._entries.size;
  }

  /** Returns the names of all registered providers. */
  get registeredProviders(): readonly string[] {
    return Array.from(this._entries.keys());
  }
}

/**
 * @module Bootstrap
 *
 * The single entry point for constructing a fully wired Voice Engine runtime.
 *
 * ## Purpose
 * `createVoiceEngineRuntime()` orchestrates environment loading, config
 * merging, DI container construction, and service registration. It returns
 * an immutable runtime object that future modules plug into.
 *
 * ## Ownership
 * Called once per process startup by the application server. The returned
 * `VoiceEngineRuntime` is shared across all concurrent calls.
 *
 * ## Thread Safety
 * `createVoiceEngineRuntime()` is not reentrant — call it once and cache
 * the result. The returned runtime object is fully thread-safe after creation.
 *
 * ## Lifecycle
 * ```
 * createVoiceEngineRuntime(options?)
 *   └─► loadEnvironment()           — read + validate process.env
 *         └─► loadConfig(env, overrides)  — merge, validate, freeze config
 *               └─► new DependencyContainer()
 *                     └─► register core services (logger, metrics, health)
 *                           └─► register provider stubs (slots for future impls)
 *                                 └─► seal container
 *                                       └─► return VoiceEngineRuntime
 * ```
 *
 * ## Extension Points
 * Callers supply concrete provider implementations through `BootstrapOptions`.
 * The bootstrap layer never instantiates providers itself.
 */

import { loadEnvironment } from './EnvironmentLoader.js';
import { loadConfig } from './ConfigLoader.js';
import type { ConfigOverrides } from './ConfigLoader.js';
import { DependencyContainer, token } from './DependencyContainer.js';
import { ProviderResolver, Tokens } from './ProviderResolver.js';
import { HealthRegistry } from './HealthRegistry.js';
import type { VoiceEngineConfig } from '../config/index.js';
import type { ILogger } from '../logger/index.js';
import type { IMetricsCollector } from '../metrics/index.js';
import type {
  ITelephonyProvider,
  ISTTProvider,
  ILLMProvider,
  ITTSProvider,
} from '../interfaces/index.js';
import type { ReadyStatus } from '../monitoring/index.js';

/** DI token for the frozen config object. */
export const CONFIG_TOKEN = token<Readonly<VoiceEngineConfig>>('VoiceEngineConfig');

/** DI token for the provider resolver. */
export const PROVIDER_RESOLVER_TOKEN = token<ProviderResolver>('ProviderResolver');

/**
 * Options accepted by `createVoiceEngineRuntime()`.
 *
 * All provider fields are optional at bootstrap time. If omitted, resolving
 * that provider token will throw until a concrete implementation is registered
 * by a future module.
 */
export interface BootstrapOptions {
  /** Programmatic configuration overrides applied after environment loading. */
  readonly configOverrides?: ConfigOverrides;

  /**
   * Concrete provider implementations to register into the DI container.
   * These are the only injection points the bootstrap accepts.
   * The bootstrap itself never creates provider implementations.
   */
  readonly providers?: {
    readonly logger?: ILogger;
    readonly metrics?: IMetricsCollector;
    readonly telephony?: ITelephonyProvider;
    readonly stt?: ISTTProvider;
    readonly llm?: ILLMProvider;
    readonly tts?: ITTSProvider;
  };
}

/**
 * The immutable runtime object returned by `createVoiceEngineRuntime()`.
 *
 * This is the root dependency for every future Voice Engine module.
 */
export interface VoiceEngineRuntime {
  /** The frozen, validated configuration for this runtime. */
  readonly config: Readonly<VoiceEngineConfig>;

  /**
   * The sealed DI container.
   * Future modules should resolve dependencies from here rather than
   * importing them directly.
   */
  readonly container: DependencyContainer;

  /**
   * Role-based provider resolver backed by the DI container.
   * Use this to access logger, metrics, and provider instances.
   */
  readonly resolver: ProviderResolver;

  /**
   * The health registry. Future providers register their health callbacks here.
   */
  readonly healthRegistry: HealthRegistry;

  /**
   * Convenience method — delegates to `healthRegistry.getReadyStatus()`.
   */
  getReadyStatus(): Promise<ReadyStatus>;

  /**
   * Releases all DI container registrations.
   * Must be called during process shutdown.
   */
  shutdown(): void;
}

/**
 * Constructs and returns a fully wired, immutable `VoiceEngineRuntime`.
 *
 * @param options - Optional providers and config overrides.
 * @throws {ConfigurationError} if environment or config validation fails.
 *
 * @example
 * ```typescript
 * const runtime = createVoiceEngineRuntime({
 *   providers: {
 *     logger: myPinoLogger,
 *     metrics: myPrometheusCollector,
 *   },
 * });
 * ```
 */
export function createVoiceEngineRuntime(
  options: BootstrapOptions = {}
): VoiceEngineRuntime {
  const env = loadEnvironment();
  const config = loadConfig(env, options.configOverrides ?? {});

  const container = new DependencyContainer();
  const healthRegistry = new HealthRegistry();

  container.registerInstance(CONFIG_TOKEN, config, true);
  container.registerInstance(Tokens.HEALTH_REGISTRY, healthRegistry, true);

  if (options.providers?.logger) {
    container.registerInstance(Tokens.LOGGER, options.providers.logger, true);
  }

  if (options.providers?.metrics) {
    container.registerInstance(Tokens.METRICS, options.providers.metrics, true);
  }

  if (options.providers?.telephony) {
    container.registerInstance(Tokens.TELEPHONY_PROVIDER, options.providers.telephony);
  }

  if (options.providers?.stt) {
    container.registerInstance(Tokens.STT_PROVIDER, options.providers.stt);
  }

  if (options.providers?.llm) {
    container.registerInstance(Tokens.LLM_PROVIDER, options.providers.llm);
  }

  if (options.providers?.tts) {
    container.registerInstance(Tokens.TTS_PROVIDER, options.providers.tts);
  }

  const resolver = new ProviderResolver(container);
  container.registerInstance(PROVIDER_RESOLVER_TOKEN, resolver, true);

  container.seal();

  return Object.freeze({
    config,
    container,
    resolver,
    healthRegistry,

    getReadyStatus(): Promise<ReadyStatus> {
      return healthRegistry.getReadyStatus();
    },

    shutdown(): void {
      container.clear();
    },
  });
}

/**
 * @module bootstrap
 *
 * Public barrel export for the Voice Engine bootstrap layer.
 *
 * ## Usage
 * ```typescript
 * import { createVoiceEngineRuntime } from '../voice-engine/bootstrap/index.js';
 * ```
 */

export { loadEnvironment } from './EnvironmentLoader.js';
export type { LoadedEnvironment } from './EnvironmentLoader.js';

export { loadConfig } from './ConfigLoader.js';
export type { ConfigOverrides } from './ConfigLoader.js';

export { DependencyContainer, token } from './DependencyContainer.js';
export type { Token } from './DependencyContainer.js';

export { ProviderResolver, Tokens } from './ProviderResolver.js';
export type { IProviderResolver } from './ProviderResolver.js';

export { HealthRegistry } from './HealthRegistry.js';
export type { HealthCallback } from './HealthRegistry.js';

export {
  createVoiceEngineRuntime,
  CONFIG_TOKEN,
  PROVIDER_RESOLVER_TOKEN,
} from './Bootstrap.js';
export type { BootstrapOptions, VoiceEngineRuntime } from './Bootstrap.js';

