/**
 * @module TurnPolicy
 *
 * Configuration that governs how a `ConversationOrchestrator` manages the
 * timing and retry behaviour of each conversational turn.
 *
 * ## Purpose
 * Centralises all time-bound constraints into one validated object.
 * No business logic lives here — only values and their validation rules.
 *
 * ## Ownership
 * Created once per orchestrator instance by `OrchestratorFactory`.
 * Immutable after construction; shared across all turns in the conversation.
 */

import { z } from 'zod';

const TurnRetryPolicySchema = z.object({
  /**
   * Maximum number of times the orchestrator will retry a failed turn
   * before escalating to a FAILED conversation state.
   */
  maxRetryAttempts: z.number().int().nonnegative().default(2),

  /**
   * Milliseconds to wait before retrying a failed turn.
   */
  retryDelayMs: z.number().int().nonnegative().default(500),
});

export const TurnPolicySchema = z.object({
  /**
   * Maximum number of consecutive barge-ins allowed within a single turn
   * before the orchestrator treats the interruption as a hard stop.
   */
  maxInterruptDepth: z.number().int().min(0).max(10).default(3),

  /**
   * Milliseconds of caller silence after which the orchestrator transitions
   * from LISTENING to WAITING and may re-engage the caller.
   */
  maxSilenceMs: z.number().int().positive().default(5_000),

  /**
   * Maximum milliseconds allowed for the LLM to produce a complete response
   * from the moment the user utterance is committed.
   */
  responseTimeoutMs: z.number().int().positive().default(15_000),

  /**
   * Maximum wall-clock duration for a single conversational turn
   * (CREATED → terminal state). If exceeded, the turn is failed.
   */
  turnTimeoutMs: z.number().int().positive().default(30_000),

  /**
   * Maximum number of turns in one conversation before the orchestrator
   * gracefully completes the session.
   */
  maxTurns: z.number().int().positive().default(50),

  /**
   * Retry policy applied when an individual turn fails due to a transient
   * provider error.
   */
  retry: TurnRetryPolicySchema.default({}),
});

export type TurnPolicy = z.infer<typeof TurnPolicySchema>;
export type TurnRetryPolicy = z.infer<typeof TurnRetryPolicySchema>;

/**
 * Parses and validates a partial policy object, applying defaults for
 * every field that is not explicitly provided.
 *
 * @throws {Error} if any provided value fails validation.
 */
export function buildTurnPolicy(partial: Partial<TurnPolicy> = {}): TurnPolicy {
  const result = TurnPolicySchema.safeParse(partial);
  if (!result.success) {
    throw new Error(
      `TurnPolicy validation failed: ${result.error.issues.map((i) => i.message).join(', ')}`
    );
  }
  return Object.freeze(result.data) as TurnPolicy;
}

/**
 * @module ConversationTurn
 *
 * An immutable record of one request–response exchange within a live call.
 *
 * ## Purpose
 * `ConversationTurn` captures the complete lifecycle of a single turn:
 * who spoke, what was said, what the response was, all latency measurements,
 * and whether the turn was interrupted. It is append-only — completed turns
 * are never modified.
 *
 * ## Ownership
 * Turns are created by the `ConversationOrchestrator` and stored in
 * `ConversationContext.history`. They are not persisted by this module.
 *
 * ## Thread Safety
 * All public properties are readonly. The builder pattern produces a new
 * sealed object at each step; no in-place mutation occurs.
 */

import type { Timestamp, Nullable } from '../types/index.js';
import { TurnState } from './TurnState.js';

/**
 * Latency breakdown recorded at turn completion.
 */
export interface TurnLatency {
  /** Milliseconds from turn creation to first audio chunk received. */
  readonly listenStartMs: Nullable<number>;
  /** Milliseconds from utterance end to LLM request dispatch. */
  readonly sttLatencyMs: Nullable<number>;
  /** Milliseconds from LLM request to first response token. */
  readonly llmLatencyMs: Nullable<number>;
  /** Milliseconds from first LLM token to first audio chunk sent. */
  readonly ttsLatencyMs: Nullable<number>;
  /** Total wall-clock duration of the turn (CREATED → terminal state). */
  readonly totalMs: Nullable<number>;
}

/**
 * Recorded interruption within a turn.
 */
export interface TurnInterruption {
  /** Timestamp when the barge-in was detected. */
  readonly detectedAt: Timestamp;
  /** Milliseconds into the response at which the interruption occurred. */
  readonly responseOffsetMs: number;
}

/**
 * Immutable record of a single conversational exchange.
 */
export interface ConversationTurn {
  /** Unique identifier for this turn (UUID-like string). */
  readonly turnId: string;
  /** Zero-based index within the conversation. */
  readonly turnIndex: number;
  /** Who initiated this turn. */
  readonly speaker: 'user' | 'system';
  /** Current lifecycle state of this turn. */
  readonly state: TurnState;
  /** Timestamp when this turn was created. */
  readonly createdAt: Timestamp;
  /** Timestamp when the utterance recording started, or null if not yet begun. */
  readonly listeningStartedAt: Nullable<Timestamp>;
  /** Timestamp when the utterance was committed for processing. */
  readonly utteranceCommittedAt: Nullable<Timestamp>;
  /** Timestamp when the response started streaming to the caller. */
  readonly responseStartedAt: Nullable<Timestamp>;
  /** Timestamp when this turn reached a terminal state. */
  readonly completedAt: Nullable<Timestamp>;
  /** The final caller transcript for this turn, or null if not yet available. */
  readonly transcript: Nullable<string>;
  /** The assistant's response text, or null if not yet generated. */
  readonly response: Nullable<string>;
  /** Latency measurements, populated progressively as the turn advances. */
  readonly latency: TurnLatency;
  /** Interruption events that occurred during this turn. */
  readonly interruptions: readonly TurnInterruption[];
  /** Number of retry attempts made for this turn due to transient errors. */
  readonly retryCount: number;
  /** Error message if the turn reached the FAILED state. */
  readonly failureReason: Nullable<string>;
}

/**
 * Creates a new turn in the CREATED state.
 */
export function createTurn(
  turnId: string,
  turnIndex: number,
  speaker: 'user' | 'system',
  now: Timestamp
): ConversationTurn {
  return Object.freeze<ConversationTurn>({
    turnId,
    turnIndex,
    speaker,
    state: TurnState.CREATED,
    createdAt: now,
    listeningStartedAt: null,
    utteranceCommittedAt: null,
    responseStartedAt: null,
    completedAt: null,
    transcript: null,
    response: null,
    latency: Object.freeze<TurnLatency>({
      listenStartMs: null,
      sttLatencyMs: null,
      llmLatencyMs: null,
      ttsLatencyMs: null,
      totalMs: null,
    }),
    interruptions: Object.freeze([]),
    retryCount: 0,
    failureReason: null,
  });
}

/**
 * Produces a new `ConversationTurn` with the applied patch merged in.
 * The original turn is never modified.
 */
export function patchTurn(
  turn: ConversationTurn,
  patch: Partial<Omit<ConversationTurn, 'turnId' | 'turnIndex' | 'createdAt'>>
): ConversationTurn {
  return Object.freeze<ConversationTurn>({
    ...turn,
    ...patch,
    latency: Object.freeze({ ...turn.latency, ...patch.latency }),
    interruptions: patch.interruptions
      ? Object.freeze([...patch.interruptions])
      : turn.interruptions,
  });
}

/**
 * Returns a new turn with one additional interruption appended.
 */
export function recordInterruption(
  turn: ConversationTurn,
  interruption: TurnInterruption
): ConversationTurn {
  return patchTurn(turn, {
    state: TurnState.INTERRUPTED,
    interruptions: [...turn.interruptions, interruption],
  });
}

/**
 * Returns a new turn sealed as COMPLETED with full latency data.
 */
export function completeTurn(
  turn: ConversationTurn,
  response: string,
  now: Timestamp
): ConversationTurn {
  const totalMs = now - turn.createdAt;
  return patchTurn(turn, {
    state: TurnState.COMPLETED,
    response,
    completedAt: now,
    latency: { ...turn.latency, totalMs },
  });
}

/**
 * Returns a new turn sealed as FAILED with a reason.
 */
export function failTurn(
  turn: ConversationTurn,
  reason: string,
  now: Timestamp
): ConversationTurn {
  return patchTurn(turn, {
    state: TurnState.FAILED,
    failureReason: reason,
    completedAt: now,
    latency: { ...turn.latency, totalMs: now - turn.createdAt },
  });
}

/**
 * @module InterruptManager
 *
 * Tracks and arbitrates barge-in (interruption) requests during a live call.
 *
 * ## Purpose
 * Provides a single place to gate, track, and acknowledge interruption events.
 * The orchestrator consults `InterruptManager` before acting on a barge-in
 * signal to enforce the `TurnPolicy.maxInterruptDepth` constraint and avoid
 * duplicate interruption handling.
 *
 * ## Ownership
 * One `InterruptManager` instance is created per `ConversationOrchestrator`.
 * Shared mutable state is confined to this object; no external code modifies
 * interruption state directly.
 *
 * ## Thread Safety
 * All methods are synchronous. The orchestrator must call them sequentially
 * from its async pipeline to avoid race conditions.
 */

import type { Timestamp, Nullable } from '../types/index.js';
import type { TurnPolicy } from './TurnPolicy.js';

/**
 * A recorded interruption request, created by `InterruptManager.request()`.
 */
export interface InterruptRequest {
  /** Monotonically increasing identifier for this interrupt request. */
  readonly requestId: number;
  /** When the barge-in signal was received. */
  readonly requestedAt: Timestamp;
  /** Whether this request has been acknowledged by the orchestrator. */
  acknowledged: boolean;
  /** When the acknowledgement was recorded, or null if not yet acknowledged. */
  acknowledgedAt: Nullable<Timestamp>;
}

/**
 * Manages barge-in state for one conversation.
 *
 * Lifecycle per interrupt:
 * 1. `request(now)`      — caller audio detected; interrupt is gated against policy.
 * 2. `acknowledge(now)`  — orchestrator confirms it has cancelled the active response.
 * 3. `clear()`           — interrupt cycle complete; ready for next turn.
 */
export class InterruptManager {
  private readonly _policy: TurnPolicy;
  private _activeRequest: Nullable<InterruptRequest> = null;
  private _totalInterruptions = 0;
  private _nextRequestId = 1;

  constructor(policy: TurnPolicy) {
    this._policy = policy;
  }

  // ─── Queries ──────────────────────────────────────────────────────────────

  /** Whether an interruption is currently pending acknowledgement. */
  get isPending(): boolean {
    return this._activeRequest !== null && !this._activeRequest.acknowledged;
  }

  /** Whether the active interruption has been acknowledged. */
  get isAcknowledged(): boolean {
    return this._activeRequest?.acknowledged === true;
  }

  /** Whether any interruption is active (pending or acknowledged). */
  get isActive(): boolean {
    return this._activeRequest !== null;
  }

  /** Total number of interruptions recorded in this conversation. */
  get totalInterruptions(): number {
    return this._totalInterruptions;
  }

  /** The active interrupt request, or null if none. */
  get activeRequest(): Nullable<Readonly<InterruptRequest>> {
    return this._activeRequest;
  }

  // ─── Commands ─────────────────────────────────────────────────────────────

  /**
   * Records an interrupt request if policy allows.
   *
   * Returns `true` if the interrupt was accepted (the orchestrator should act
   * on it). Returns `false` if the policy has been exceeded or a request is
   * already active.
   *
   * @param now - Current timestamp from the orchestrator's clock.
   */
  request(now: Timestamp): boolean {
    if (this._activeRequest !== null) {
      return false;
    }

    if (this._totalInterruptions >= this._policy.maxInterruptDepth) {
      return false;
    }

    this._activeRequest = {
      requestId: this._nextRequestId++,
      requestedAt: now,
      acknowledged: false,
      acknowledgedAt: null,
    };

    return true;
  }

  /**
   * Acknowledges the active interrupt request, recording that the orchestrator
   * has cancelled the in-progress response.
   *
   * @param now - Current timestamp.
   * @returns `true` if acknowledgement was recorded; `false` if no pending request.
   */
  acknowledge(now: Timestamp): boolean {
    if (!this._activeRequest || this._activeRequest.acknowledged) {
      return false;
    }

    this._activeRequest.acknowledged = true;
    this._activeRequest.acknowledgedAt = now;
    this._totalInterruptions += 1;
    return true;
  }

  /**
   * Clears the active interrupt, resetting the manager for the next turn.
   * Must be called after the orchestrator has started listening again.
   */
  clear(): void {
    this._activeRequest = null;
  }

  /**
   * Resets the manager entirely (e.g. on conversation restart).
   */
  reset(): void {
    this._activeRequest = null;
    this._totalInterruptions = 0;
    this._nextRequestId = 1;
  }
}

/**
 * @module TurnScheduler
 *
 * Makes scheduling decisions for conversational turns without owning any
 * timer resources.
 *
 * ## Purpose
 * The `TurnScheduler` is a pure decision-maker. It evaluates the current
 * conversation state and returns a `SchedulingDecision` telling the
 * orchestrator what to do next. No `setTimeout`, no I/O, no side effects.
 *
 * ## Ownership
 * One `TurnScheduler` per `ConversationOrchestrator`. The orchestrator calls
 * `decide()` after each significant event and acts on the result.
 *
 * ## Thread Safety
 * All methods are synchronous and pure with respect to the inputs. No shared
 * mutable state beyond the `_turnCount` counter.
 */

import type { Timestamp, Nullable } from '../types/index.js';
import type { TurnPolicy } from './TurnPolicy.js';
import { TurnState } from './TurnState.js';
import type { ConversationTurn } from './ConversationTurn.js';

/**
 * The action the orchestrator should take next, as determined by the scheduler.
 */
export type SchedulingAction =
  | 'start_listening'   // Begin the next turn's audio capture.
  | 'start_processing'  // Commit utterance and trigger LLM.
  | 'start_responding'  // Begin streaming response to caller.
  | 'handle_interrupt'  // Cancel current response, prepare for new turn.
  | 'retry_turn'        // Retry the current failed turn (within retry limit).
  | 'complete'          // Gracefully end the conversation.
  | 'wait'              // No action yet — await next event.
  | 'fail';             // Irrecoverable state — surface a fatal error.

/**
 * A scheduling decision returned by `TurnScheduler.decide()`.
 */
export interface SchedulingDecision {
  /** The recommended next action. */
  readonly action: SchedulingAction;
  /** Human-readable reason for the decision (for logging only). */
  readonly reason: string;
  /**
   * For `retry_turn` — the delay in milliseconds to wait before retrying,
   * based on the policy's retry delay configuration.
   */
  readonly retryDelayMs?: number;
}

/**
 * Snapshot of conversation state passed to `TurnScheduler.decide()`.
 */
export interface SchedulingInput {
  /** The current active turn, or null between turns. */
  readonly currentTurn: Nullable<ConversationTurn>;
  /** The most recently completed turn, or null on the first turn. */
  readonly previousTurn: Nullable<ConversationTurn>;
  /** Total number of completed turns so far. */
  readonly completedTurnCount: number;
  /** Whether an interrupt is currently active and pending acknowledgement. */
  readonly interruptPending: boolean;
  /** Whether a silence timeout has been signalled since the last reset. */
  readonly silenceTimeout: boolean;
  /** Whether a response generation timeout has fired. */
  readonly responseTimeout: boolean;
  /** Whether a session-level timeout has fired. */
  readonly sessionTimeout: boolean;
  /** Current wall-clock time from the orchestrator's clock. */
  readonly now: Timestamp;
}

/**
 * Pure scheduling decision engine for conversational turns.
 */
export class TurnScheduler {
  private readonly _policy: TurnPolicy;

  constructor(policy: TurnPolicy) {
    this._policy = policy;
  }

  /**
   * Evaluates the current conversation state and returns the next action
   * the orchestrator should take.
   *
   * Called after every significant event: turn state changes, timeouts,
   * interrupts, provider events.
   */
  decide(input: SchedulingInput): SchedulingDecision {
    const { currentTurn, completedTurnCount, interruptPending, silenceTimeout, responseTimeout, sessionTimeout } = input;

    if (sessionTimeout) {
      return { action: 'complete', reason: 'Session wall-clock timeout reached' };
    }

    if (completedTurnCount >= this._policy.maxTurns) {
      return { action: 'complete', reason: `Maximum turn count reached (${this._policy.maxTurns})` };
    }

    if (currentTurn === null) {
      return { action: 'start_listening', reason: 'No active turn — beginning first turn' };
    }

    const state = currentTurn.state;

    if (interruptPending && state === TurnState.RESPONDING) {
      return { action: 'handle_interrupt', reason: 'Barge-in detected during response' };
    }

    if (state === TurnState.INTERRUPTED) {
      return { action: 'start_listening', reason: 'Interrupt acknowledged — starting new turn' };
    }

    if (state === TurnState.COMPLETED) {
      return { action: 'start_listening', reason: 'Turn completed — starting next turn' };
    }

    if (state === TurnState.FAILED) {
      if (currentTurn.retryCount < this._policy.retry.maxRetryAttempts) {
        return {
          action: 'retry_turn',
          reason: `Turn failed — retry ${currentTurn.retryCount + 1} of ${this._policy.retry.maxRetryAttempts}`,
          retryDelayMs: this._policy.retry.retryDelayMs,
        };
      }
      return { action: 'fail', reason: 'Turn failed and retry limit exceeded' };
    }

    if (state === TurnState.LISTENING) {
      if (silenceTimeout) {
        return { action: 'complete', reason: 'Silence timeout exceeded in LISTENING state' };
      }
      return { action: 'wait', reason: 'Waiting for caller utterance' };
    }

    if (state === TurnState.PROCESSING) {
      if (responseTimeout) {
        return { action: 'fail', reason: 'Response generation timeout exceeded' };
      }
      return { action: 'wait', reason: 'Waiting for LLM response' };
    }

    if (state === TurnState.RESPONDING) {
      return { action: 'wait', reason: 'Response streaming to caller' };
    }

    if (state === TurnState.CREATED) {
      return { action: 'start_listening', reason: 'Turn created — starting audio capture' };
    }

    return { action: 'wait', reason: `No action determined for turn state: ${state}` };
  }

  /**
   * Returns `true` if a response timeout should be fired based on elapsed time.
   *
   * @param responseStartedAt - When the PROCESSING state was entered, or null.
   * @param now - Current timestamp.
   */
  isResponseTimedOut(responseStartedAt: Nullable<Timestamp>, now: Timestamp): boolean {
    if (responseStartedAt === null) return false;
    return now - responseStartedAt > this._policy.responseTimeoutMs;
  }

  /**
   * Returns `true` if the silence policy threshold has been exceeded.
   *
   * @param lastAudioAt - Timestamp of the last non-silent audio chunk, or null.
   * @param now - Current timestamp.
   */
  isSilenceTimedOut(lastAudioAt: Nullable<Timestamp>, now: Timestamp): boolean {
    if (lastAudioAt === null) return false;
    return now - lastAudioAt > this._policy.maxSilenceMs;
  }

  /**
   * Returns `true` if the current turn has exceeded its maximum wall-clock duration.
   *
   * @param turnCreatedAt - When the current turn was created.
   * @param now - Current timestamp.
   */
  isTurnTimedOut(turnCreatedAt: Timestamp, now: Timestamp): boolean {
    return now - turnCreatedAt > this._policy.turnTimeoutMs;
  }
}

/**
 * @module ConversationContext
 *
 * Mutable accumulator of all state that changes over the lifetime of a
 * single live conversation.
 *
 * ## Purpose
 * `ConversationContext` is the only place inside the orchestrator that
 * intentionally holds mutable state. It tracks the current and previous
 * turn, conversation history, active instructions, and references to the
 * frozen campaign and knowledge snapshots.
 *
 * ## Ownership
 * Created by the `ConversationOrchestrator` at conversation start and
 * discarded on shutdown. Not persisted — persistence is handled by the
 * session layer above the orchestrator.
 *
 * ## Thread Safety
 * All mutations must be performed by the orchestrator's sequential async
 * pipeline. No concurrent writes are safe.
 */

import type { Timestamp, Nullable, SessionId, CampaignId } from '../types/index.js';
import type { ConversationTurn } from './ConversationTurn.js';
import type { CampaignSnapshot } from '../session/index.js';
import type { KnowledgeSnapshot } from '../runtime/RuntimeContext.js';

/**
 * A registered tool available to the LLM in the current context.
 */
export interface ToolDefinition {
  readonly name: string;
  readonly description: string;
  readonly parametersSchema: Readonly<Record<string, unknown>>;
}

/**
 * A pending tool call from the LLM awaiting a result submission.
 */
export interface PendingToolCall {
  readonly callId: string;
  readonly toolName: string;
  readonly argumentsJson: string;
  readonly receivedAt: Timestamp;
}

/**
 * A summarised representation of a completed turn stored in conversation memory.
 */
export interface TurnMemoryEntry {
  readonly turnIndex: number;
  readonly userTranscript: Nullable<string>;
  readonly assistantResponse: Nullable<string>;
  readonly completedAt: Nullable<Timestamp>;
  readonly wasInterrupted: boolean;
}

/**
 * The mutable context object owned by one `ConversationOrchestrator`.
 */
export class ConversationContext {
  /** Unique identifier of the session this conversation belongs to. */
  readonly sessionId: SessionId;

  /** Campaign this conversation is executing. */
  readonly campaignId: CampaignId;

  /** Frozen campaign configuration snapshot. */
  readonly campaign: Readonly<CampaignSnapshot>;

  /** Frozen knowledge base snapshot for this campaign. */
  readonly knowledge: Readonly<KnowledgeSnapshot>;

  /** Conversation start timestamp. */
  readonly startedAt: Timestamp;

  private _currentTurn: Nullable<ConversationTurn> = null;
  private _previousTurn: Nullable<ConversationTurn> = null;
  private _history: TurnMemoryEntry[] = [];
  private _instructions: string;
  private _tools: ToolDefinition[] = [];
  private _pendingToolCalls: Map<string, PendingToolCall> = new Map();
  private _completedTurnCount = 0;
  private _lastActivityAt: Timestamp;

  constructor(
    sessionId: SessionId,
    campaignId: CampaignId,
    campaign: Readonly<CampaignSnapshot>,
    knowledge: Readonly<KnowledgeSnapshot>,
    initialInstructions: string,
    now: Timestamp
  ) {
    this.sessionId = sessionId;
    this.campaignId = campaignId;
    this.campaign = campaign;
    this.knowledge = knowledge;
    this._instructions = initialInstructions;
    this.startedAt = now;
    this._lastActivityAt = now;
  }

  // ─── Turn Management ──────────────────────────────────────────────────────

  /**
   * The turn currently being processed. Null between turns.
   */
  get currentTurn(): Nullable<ConversationTurn> {
    return this._currentTurn;
  }

  /**
   * The turn that completed immediately before the current one.
   */
  get previousTurn(): Nullable<ConversationTurn> {
    return this._previousTurn;
  }

  /**
   * Total number of turns that have reached a terminal state.
   */
  get completedTurnCount(): number {
    return this._completedTurnCount;
  }

  /**
   * Sets the current active turn. The previous turn is not modified here;
   * call `archiveTurn()` to rotate turns on completion.
   */
  setCurrentTurn(turn: ConversationTurn): void {
    this._currentTurn = turn;
  }

  /**
   * Moves the current turn to `previousTurn`, increments the completed count,
   * appends a memory entry, and clears `currentTurn`.
   */
  archiveTurn(completedTurn: ConversationTurn, now: Timestamp): void {
    const entry: TurnMemoryEntry = {
      turnIndex: completedTurn.turnIndex,
      userTranscript: completedTurn.transcript,
      assistantResponse: completedTurn.response,
      completedAt: completedTurn.completedAt,
      wasInterrupted: completedTurn.interruptions.length > 0,
    };
    this._history.push(entry);
    this._previousTurn = completedTurn;
    this._currentTurn = null;
    this._completedTurnCount += 1;
    this._lastActivityAt = now;
  }

  // ─── Conversation Memory ──────────────────────────────────────────────────

  /**
   * Ordered history of completed turns, oldest first.
   */
  get history(): readonly TurnMemoryEntry[] {
    return this._history;
  }

  // ─── Instructions ─────────────────────────────────────────────────────────

  /**
   * The current system instructions sent to the LLM provider.
   */
  get instructions(): string {
    return this._instructions;
  }

  /**
   * Replaces the active instructions (e.g. dynamic prompt updates mid-call).
   */
  updateInstructions(instructions: string, now: Timestamp): void {
    this._instructions = instructions;
    this._lastActivityAt = now;
  }

  // ─── Tool Context ─────────────────────────────────────────────────────────

  /**
   * Tools currently registered for this conversation.
   */
  get tools(): readonly ToolDefinition[] {
    return this._tools;
  }

  /**
   * Replaces the set of available tools.
   */
  setTools(tools: readonly ToolDefinition[], now: Timestamp): void {
    this._tools = [...tools];
    this._lastActivityAt = now;
  }

  /**
   * Records a pending tool call awaiting a result.
   */
  addPendingToolCall(call: PendingToolCall): void {
    this._pendingToolCalls.set(call.callId, call);
  }

  /**
   * Returns and removes a pending tool call by callId, or null if not found.
   */
  consumePendingToolCall(callId: string): Nullable<PendingToolCall> {
    const call = this._pendingToolCalls.get(callId) ?? null;
    if (call) this._pendingToolCalls.delete(callId);
    return call;
  }

  /**
   * All pending tool calls awaiting results.
   */
  get pendingToolCalls(): readonly PendingToolCall[] {
    return Array.from(this._pendingToolCalls.values());
  }

  // ─── Activity ─────────────────────────────────────────────────────────────

  /**
   * Timestamp of the most recent state change in this context.
   */
  get lastActivityAt(): Timestamp {
    return this._lastActivityAt;
  }

  /**
   * Updates the last activity timestamp. Call whenever external audio or
   * events arrive.
   */
  touch(now: Timestamp): void {
    this._lastActivityAt = now;
  }
}

/**
 * @module ConversationOrchestrator
 *
 * The heart of Voice Engine V2 — coordinates every live conversation.
 *
 * ## Purpose
 * `ConversationOrchestrator` is the single owner of a conversation's lifecycle.
 * It drives the runtime state machine, schedules turns, handles barge-ins, and
 * routes events between the runtime, provider session, and turn infrastructure.
 *
 * It contains NO provider-specific logic. It does NOT import OpenAI, Exotel,
 * or any transport library. All AI and telephony concerns are hidden behind
 * the abstract `IRealtimeProviderSession` interface and the provider resolver.
 *
 * ## Ownership
 * One `ConversationOrchestrator` is created per live call by `OrchestratorFactory`.
 * The caller is responsible for calling `stop()` and `destroy()` when the call ends.
 *
 * ## Thread Safety
 * Lifecycle methods (`start`, `stop`, `handleAudioChunk`, `interrupt`) must be
 * called sequentially. The orchestrator does not acquire locks internally.
 *
 * ## Lifecycle
 * ```
 * createConversationOrchestrator()
 *   └─► start()           — initialise runtime, connect session, begin first turn
 *         └─► [turn loop]  — LISTENING → PROCESSING → RESPONDING → LISTENING
 *               ├─► handleAudioChunk()  — deliver audio during LISTENING
 *               └─► interrupt()         — barge-in during RESPONDING
 *   └─► stop(reason)      — gracefully complete the conversation
 *   └─► destroy()         — forced teardown; always safe to call
 * ```
 */

import type { ConversationRuntime } from '../runtime/ConversationRuntime.js';
import type { RuntimeContext } from '../runtime/RuntimeContext.js';
import type { IProviderResolver } from '../bootstrap/ProviderResolver.js';
import type { ILogger } from '../logger/index.js';
import type { IMetricsCollector } from '../metrics/index.js';
import type { Timestamp, Nullable, SessionId } from '../types/index.js';
import type { TurnPolicy } from './TurnPolicy.js';
import type { ConversationTurn } from './ConversationTurn.js';
import { ConversationContext } from './ConversationContext.js';
import { InterruptManager } from './InterruptManager.js';
import { TurnScheduler } from './TurnScheduler.js';
import { TurnState } from './TurnState.js';
import {
  createTurn,
  patchTurn,
  completeTurn,
  failTurn,
  recordInterruption,
} from './ConversationTurn.js';
import type { TurnInterruption } from './ConversationTurn.js';
import { VoiceEngineError, ErrorCode } from '../errors/index.js';

// ─── Realtime Session Abstraction ─────────────────────────────────────────────

/**
 * Abstract interface for a real-time AI provider session.
 *
 * Implemented by provider-specific sessions (e.g. `OpenAIRealtimeSession`).
 * The orchestrator depends ONLY on this interface — no OpenAI SDK is imported here.
 */
export interface IRealtimeProviderSession {
  /** Whether the session's connection is currently open. */
  readonly isConnected: boolean;

  /** Opens the session connection. Must be called before any send methods. */
  connect(): Promise<void>;

  /**
   * Appends a base64-encoded audio chunk to the provider's input buffer.
   * Fire-and-forget — does not await server acknowledgement.
   */
  sendAudio(base64Chunk: string): void;

  /**
   * Sends a text message into the conversation and triggers a response.
   */
  sendText(text: string): Promise<void>;

  /**
   * Cancels the current in-progress response (barge-in handling).
   */
  interrupt(): Promise<void>;

  /**
   * Updates the active system instructions without closing the session.
   */
  updateInstructions(instructions: string): Promise<void>;

  /** Gracefully closes the session connection. */
  close(): Promise<void>;

  /** Registers a typed event handler on the session. */
  on(type: string, handler: (event: unknown) => void): void;

  /** Removes a previously registered event handler. */
  off(type: string, handler: (event: unknown) => void): void;
}

// ─── Orchestrator State ───────────────────────────────────────────────────────

/**
 * Lifecycle states of the `ConversationOrchestrator` itself.
 * Distinct from `TurnState` (per-turn) and `RuntimeState` (low-level).
 */
export enum OrchestratorState {
  IDLE        = 'IDLE',
  STARTING    = 'STARTING',
  RUNNING     = 'RUNNING',
  STOPPING    = 'STOPPING',
  COMPLETED   = 'COMPLETED',
  FAILED      = 'FAILED',
  DESTROYED   = 'DESTROYED',
}

// ─── Orchestrator Events ──────────────────────────────────────────────────────

export type OrchestratorEventType =
  | 'orchestrator.started'
  | 'orchestrator.turn_started'
  | 'orchestrator.turn_completed'
  | 'orchestrator.turn_failed'
  | 'orchestrator.interrupted'
  | 'orchestrator.completed'
  | 'orchestrator.failed'
  | 'orchestrator.destroyed';

export interface OrchestratorEvent {
  readonly type: OrchestratorEventType;
  readonly timestamp: Timestamp;
  readonly sessionId: SessionId;
  readonly payload: Readonly<Record<string, unknown>>;
}

export type OrchestratorEventHandler = (event: OrchestratorEvent) => void;

// ─── Orchestrator Interface ───────────────────────────────────────────────────

/**
 * Public contract for a single conversation orchestrator instance.
 */
export interface IConversationOrchestrator {
  /** Current lifecycle state of the orchestrator. */
  readonly state: OrchestratorState;

  /**
   * Initialises and connects all resources, then begins the first turn.
   * Transitions: IDLE → STARTING → RUNNING.
   *
   * @throws {VoiceEngineError} if startup fails.
   */
  start(): Promise<void>;

  /**
   * Gracefully ends the conversation.
   * Transitions: RUNNING → STOPPING → COMPLETED.
   *
   * @param reason - Human-readable reason for stopping.
   */
  stop(reason?: string): Promise<void>;

  /**
   * Delivers a base64-encoded audio chunk to the provider session.
   * Only has effect while the orchestrator is RUNNING.
   */
  handleAudioChunk(base64Chunk: string, now: Timestamp): void;

  /**
   * Signals a barge-in. The orchestrator will cancel the current response
   * and return to LISTENING if policy allows.
   */
  interrupt(now: Timestamp): Promise<void>;

  /**
   * Returns the current conversation context (read-only view).
   */
  getContext(): Readonly<ConversationContext>;

  /** Subscribes to orchestrator lifecycle events. */
  on(type: OrchestratorEventType, handler: OrchestratorEventHandler): void;

  /** Unsubscribes from orchestrator lifecycle events. */
  off(type: OrchestratorEventType, handler: OrchestratorEventHandler): void;

  /**
   * Forces an immediate teardown from any state.
   * Safe to call multiple times; subsequent calls are no-ops.
   */
  destroy(): void;
}

// ─── Implementation ───────────────────────────────────────────────────────────

/**
 * Production implementation of `IConversationOrchestrator`.
 */
export class ConversationOrchestrator implements IConversationOrchestrator {
  private readonly _runtime: ConversationRuntime;
  private readonly _session: IRealtimeProviderSession;
  private readonly _resolver: IProviderResolver;
  private readonly _context: ConversationContext;
  private readonly _interruptManager: InterruptManager;
  private readonly _scheduler: TurnScheduler;
  private readonly _policy: TurnPolicy;
  private readonly _logger: ILogger;
  private readonly _metrics: IMetricsCollector;
  private readonly _clock: RuntimeContext['clock'];

  private _state: OrchestratorState = OrchestratorState.IDLE;
  private _turnIndex = 0;
  private _nextTurnId = 1;

  private readonly _handlers = new Map<OrchestratorEventType, Set<OrchestratorEventHandler>>();

  constructor(deps: {
    runtime: ConversationRuntime;
    session: IRealtimeProviderSession;
    resolver: IProviderResolver;
    context: ConversationContext;
    policy: TurnPolicy;
    logger: ILogger;
    metrics: IMetricsCollector;
    clock: RuntimeContext['clock'];
  }) {
    this._runtime = deps.runtime;
    this._session = deps.session;
    this._resolver = deps.resolver;
    this._context = deps.context;
    this._policy = deps.policy;
    this._logger = deps.logger.child({ component: 'ConversationOrchestrator', sessionId: deps.context.sessionId });
    this._metrics = deps.metrics;
    this._clock = deps.clock;
    this._interruptManager = new InterruptManager(deps.policy);
    this._scheduler = new TurnScheduler(deps.policy);
  }

  // ─── Public API ─────────────────────────────────────────────────────────

  get state(): OrchestratorState {
    return this._state;
  }

  async start(): Promise<void> {
    this._assertState(OrchestratorState.IDLE, 'start');
    this._setState(OrchestratorState.STARTING);
    this._logger.info('ConversationOrchestrator starting');

    try {
      await this._runtime.initialize();
      await this._runtime.connect();
      await this._session.connect();
      this._registerSessionHandlers();

      this._setState(OrchestratorState.RUNNING);
      this._emit('orchestrator.started', {});

      await this._beginNextTurn();
    } catch (err) {
      this._setState(OrchestratorState.FAILED);
      this._emit('orchestrator.failed', { reason: String(err) });
      throw err;
    }
  }

  async stop(reason: string = 'requested'): Promise<void> {
    if (this._state !== OrchestratorState.RUNNING) return;
    this._setState(OrchestratorState.STOPPING);
    this._logger.info('ConversationOrchestrator stopping', { reason });

    await this._runtime.complete(reason);
    await this._session.close();
    await this._runtime.close();

    this._setState(OrchestratorState.COMPLETED);
    this._emit('orchestrator.completed', { reason, totalTurns: this._context.completedTurnCount });
  }

  handleAudioChunk(base64Chunk: string, now: Timestamp): void {
    if (this._state !== OrchestratorState.RUNNING) return;
    this._context.touch(now);
    this._session.sendAudio(base64Chunk);
  }

  async interrupt(now: Timestamp): Promise<void> {
    if (this._state !== OrchestratorState.RUNNING) return;

    const accepted = this._interruptManager.request(now);
    if (!accepted) {
      this._logger.debug('Interrupt request rejected by InterruptManager');
      return;
    }

    this._logger.info('Barge-in accepted — interrupting response');

    const current = this._context.currentTurn;
    if (current) {
      const interruption: TurnInterruption = {
        detectedAt: now,
        responseOffsetMs: current.responseStartedAt ? now - current.responseStartedAt : 0,
      };
      this._context.setCurrentTurn(recordInterruption(current, interruption));
    }

    await this._runtime.interrupt();
    await this._session.interrupt();
    this._interruptManager.acknowledge(now);

    this._emit('orchestrator.interrupted', { turnIndex: this._turnIndex });

    const interrupted = this._context.currentTurn;
    if (interrupted) {
      this._context.archiveTurn(interrupted, now);
    }
    this._interruptManager.clear();

    await this._beginNextTurn();
  }

  getContext(): Readonly<ConversationContext> {
    return this._context;
  }

  on(type: OrchestratorEventType, handler: OrchestratorEventHandler): void {
    if (!this._handlers.has(type)) this._handlers.set(type, new Set());
    this._handlers.get(type)!.add(handler);
  }

  off(type: OrchestratorEventType, handler: OrchestratorEventHandler): void {
    this._handlers.get(type)?.delete(handler);
  }

  destroy(): void {
    if (this._state === OrchestratorState.DESTROYED) return;
    this._logger.info('ConversationOrchestrator destroying');
    this._runtime.destroy();
    this._session.close().catch(() => undefined);
    this._setState(OrchestratorState.DESTROYED);
    this._emit('orchestrator.destroyed', {});
    this._handlers.clear();
  }

  // ─── Turn Lifecycle ──────────────────────────────────────────────────────

  private async _beginNextTurn(): Promise<void> {
    if (this._state !== OrchestratorState.RUNNING) return;

    const now = this._clock.now();
    const decision = this._scheduler.decide({
      currentTurn: this._context.currentTurn,
      previousTurn: this._context.previousTurn,
      completedTurnCount: this._context.completedTurnCount,
      interruptPending: this._interruptManager.isPending,
      silenceTimeout: false,
      responseTimeout: false,
      sessionTimeout: false,
      now,
    });

    this._logger.debug('Scheduling decision', { action: decision.action, reason: decision.reason });

    if (decision.action === 'complete') {
      await this.stop(decision.reason);
      return;
    }

    if (decision.action === 'fail') {
      this._setState(OrchestratorState.FAILED);
      this._emit('orchestrator.failed', { reason: decision.reason });
      return;
    }

    if (decision.action === 'start_listening') {
      const turn = createTurn(
        `turn_${this._nextTurnId++}`,
        this._turnIndex++,
        'user',
        now
      );
      this._context.setCurrentTurn(turn);
      this._emit('orchestrator.turn_started', { turnId: turn.turnId, turnIndex: turn.turnIndex });
      await this._runtime.startListening();
      this._context.setCurrentTurn(patchTurn(turn, { state: TurnState.LISTENING, listeningStartedAt: now }));
    }
  }

  private async _onUtteranceCompleted(transcript: string): Promise<void> {
    if (this._state !== OrchestratorState.RUNNING) return;
    const now = this._clock.now();
    let turn = this._context.currentTurn;
    if (!turn) return;

    turn = patchTurn(turn, {
      state: TurnState.PROCESSING,
      transcript,
      utteranceCommittedAt: now,
      latency: { ...turn.latency, sttLatencyMs: now - (turn.listeningStartedAt ?? now) },
    });
    this._context.setCurrentTurn(turn);
    await this._runtime.startThinking(transcript);
  }

  private async _onResponseCompleted(response: string): Promise<void> {
    if (this._state !== OrchestratorState.RUNNING) return;
    const now = this._clock.now();
    const turn = this._context.currentTurn;
    if (!turn) return;

    const completed = completeTurn(turn, response, now);
    this._context.archiveTurn(completed, now);
    this._emit('orchestrator.turn_completed', { turnId: turn.turnId, turnIndex: turn.turnIndex });

    await this._beginNextTurn();
  }

  private async _onResponseStarted(responseId: string): Promise<void> {
    if (this._state !== OrchestratorState.RUNNING) return;
    const now = this._clock.now();
    const turn = this._context.currentTurn;
    if (!turn) return;

    const withLatency = patchTurn(turn, {
      state: TurnState.RESPONDING,
      responseStartedAt: now,
      latency: {
        ...turn.latency,
        llmLatencyMs: turn.utteranceCommittedAt ? now - turn.utteranceCommittedAt : null,
      },
    });
    this._context.setCurrentTurn(withLatency);
    await this._runtime.startSpeaking(responseId);
  }

  private async _onProviderError(message: string): Promise<void> {
    const now = this._clock.now();
    const turn = this._context.currentTurn;
    if (turn) {
      const failed = failTurn(turn, message, now);
      this._context.archiveTurn(failed, now);
      this._emit('orchestrator.turn_failed', { turnId: turn.turnId, reason: message });
    }

    const decision = this._scheduler.decide({
      currentTurn: this._context.currentTurn,
      previousTurn: this._context.previousTurn,
      completedTurnCount: this._context.completedTurnCount,
      interruptPending: false,
      silenceTimeout: false,
      responseTimeout: false,
      sessionTimeout: false,
      now,
    });

    if (decision.action === 'fail') {
      this._setState(OrchestratorState.FAILED);
      this._emit('orchestrator.failed', { reason: message });
    } else {
      await this._beginNextTurn();
    }
  }

  // ─── Session Event Wiring ────────────────────────────────────────────────

  private _registerSessionHandlers(): void {
    this._session.on('realtime.transcript_completed', async (raw: unknown) => {
      const event = raw as { transcript: string };
      await this._onUtteranceCompleted(event.transcript ?? '').catch((err) => {
        this._logger.error('Error handling transcript_completed', { error: String(err) });
      });
    });

    this._session.on('realtime.response_started', async (raw: unknown) => {
      const event = raw as { responseId: string };
      await this._onResponseStarted(event.responseId ?? '').catch((err) => {
        this._logger.error('Error handling response_started', { error: String(err) });
      });
    });

    this._session.on('realtime.response_completed', async (raw: unknown) => {
      const event = raw as { status: string; responseId: string };
      if (event.status === 'completed') {
        const turn = this._context.currentTurn;
        await this._onResponseCompleted(turn?.response ?? '').catch((err) => {
          this._logger.error('Error handling response_completed', { error: String(err) });
        });
      }
    });

    this._session.on('realtime.error', async (raw: unknown) => {
      const event = raw as { message: string; fatal: boolean };
      this._logger.error('Provider session error', { message: event.message, fatal: event.fatal });
      if (event.fatal) {
        await this._onProviderError(event.message).catch(() => undefined);
      }
    });
  }

  // ─── Private Helpers ─────────────────────────────────────────────────────

  private _setState(state: OrchestratorState): void {
    this._logger.debug('OrchestratorState', { from: this._state, to: state });
    this._state = state;
  }

  private _assertState(expected: OrchestratorState, method: string): void {
    if (this._state !== expected) {
      throw new VoiceEngineError(
        `ConversationOrchestrator.${method}() called in state ${this._state}, expected ${expected}`,
        ErrorCode.PIPELINE_ABORTED,
        false
      );
    }
  }

  private _emit(type: OrchestratorEventType, payload: Record<string, unknown>): void {
    const event: OrchestratorEvent = {
      type,
      timestamp: this._clock.now(),
      sessionId: this._context.sessionId,
      payload: Object.freeze(payload),
    };
    const handlers = this._handlers.get(type);
    if (!handlers) return;
    Array.from(handlers).forEach((handler) => {
      try { handler(event); } catch { /* swallow — event delivery must not crash the orchestrator */ }
    });
  }
}

/**
 * @module OrchestratorFactory
 *
 * Dependency-injected factory for constructing `ConversationOrchestrator` instances.
 *
 * ## Purpose
 * The single authorised entry point for creating an orchestrator. Wires all
 * dependencies together — runtime, session, context, policy — without
 * containing any provider-specific or transport-specific logic.
 *
 * ## Ownership
 * Called by the call-coordinator (telephony webhook handler) once per inbound
 * or outbound call, after the session has been hydrated and a provider session
 * has been opened.
 *
 * ## Thread Safety
 * `createConversationOrchestrator()` is stateless and reentrant. Concurrent
 * calls each produce an independent orchestrator with no shared mutable state.
 */

import { ConversationOrchestrator } from './ConversationOrchestrator.js';
import type { IConversationOrchestrator, IRealtimeProviderSession } from './ConversationOrchestrator.js';
import { ConversationContext } from './ConversationContext.js';
import { buildTurnPolicy } from './TurnPolicy.js';
import type { TurnPolicy } from './TurnPolicy.js';
import type { ConversationRuntime } from '../runtime/ConversationRuntime.js';
import type { IProviderResolver } from '../bootstrap/ProviderResolver.js';
import type { IClock } from '../runtime/RuntimeContext.js';
import type { KnowledgeSnapshot } from '../runtime/RuntimeContext.js';
import type { CampaignSnapshot } from '../session/index.js';
import type { SessionId, CampaignId, Timestamp } from '../types/index.js';
import type { ILogger } from '../logger/index.js';
import type { IMetricsCollector } from '../metrics/index.js';
import { ConfigurationError } from '../errors/index.js';

/**
 * All dependencies required to construct one `ConversationOrchestrator`.
 */
export interface OrchestratorCreationOptions {
  /**
   * The live conversation runtime managing the call's state machine.
   * Must be in the CREATED state when passed to the factory.
   */
  readonly runtime: ConversationRuntime;

  /**
   * The abstract realtime provider session.
   * Implemented by provider-specific sessions (e.g. OpenAI Realtime).
   * Must not be connected yet; the orchestrator calls `connect()`.
   */
  readonly session: IRealtimeProviderSession;

  /**
   * Role-based provider resolver from the DI container.
   */
  readonly resolver: IProviderResolver;

  /**
   * Monotonic clock shared with the runtime.
   */
  readonly clock: IClock;

  /**
   * Unique session identifier for this conversation.
   */
  readonly sessionId: SessionId;

  /**
   * Campaign identifier for this conversation.
   */
  readonly campaignId: CampaignId;

  /**
   * Frozen campaign configuration snapshot.
   */
  readonly campaign: Readonly<CampaignSnapshot>;

  /**
   * Frozen knowledge base snapshot for this campaign.
   */
  readonly knowledge: Readonly<KnowledgeSnapshot>;

  /**
   * Compiled system instructions to send to the LLM provider at session start.
   */
  readonly initialInstructions: string;

  /**
   * Timestamp at which the conversation was initiated.
   */
  readonly startedAt: Timestamp;

  /**
   * Optional turn policy overrides. Missing fields fall back to defaults.
   */
  readonly policyOverrides?: Partial<TurnPolicy>;

  /**
   * Logger scoped to the call (should already contain sessionId / callSid bindings).
   */
  readonly logger: ILogger;

  /**
   * Metrics collector for emitting per-turn and per-conversation measurements.
   */
  readonly metrics: IMetricsCollector;
}

/**
 * Constructs and returns a new `ConversationOrchestrator` in the IDLE state.
 *
 * The returned orchestrator has not yet started. The caller must invoke
 * `start()` to begin the conversation.
 *
 * @param options - Wired dependencies for this conversation.
 * @returns A new orchestrator in the IDLE state.
 * @throws {ConfigurationError} if any required field in `options` is missing.
 *
 * @example
 * ```typescript
 * const orchestrator = createConversationOrchestrator({
 *   runtime,
 *   session: openAISession,     // implements IRealtimeProviderSession
 *   resolver,
 *   clock,
 *   sessionId,
 *   campaignId,
 *   campaign,
 *   knowledge,
 *   initialInstructions,
 *   startedAt: Date.now(),
 *   logger,
 *   metrics,
 * });
 *
 * await orchestrator.start();
 * ```
 */
export function createConversationOrchestrator(
  options: OrchestratorCreationOptions
): IConversationOrchestrator {
  if (!options.runtime) throw new ConfigurationError('OrchestratorFactory: runtime is required');
  if (!options.session) throw new ConfigurationError('OrchestratorFactory: session is required');
  if (!options.resolver) throw new ConfigurationError('OrchestratorFactory: resolver is required');
  if (!options.clock)   throw new ConfigurationError('OrchestratorFactory: clock is required');
  if (!options.sessionId) throw new ConfigurationError('OrchestratorFactory: sessionId is required');
  if (!options.campaignId) throw new ConfigurationError('OrchestratorFactory: campaignId is required');
  if (!options.logger)  throw new ConfigurationError('OrchestratorFactory: logger is required');
  if (!options.metrics) throw new ConfigurationError('OrchestratorFactory: metrics is required');

  const policy = buildTurnPolicy(options.policyOverrides ?? {});

  const context = new ConversationContext(
    options.sessionId,
    options.campaignId,
    options.campaign,
    options.knowledge,
    options.initialInstructions,
    options.startedAt
  );

  return new ConversationOrchestrator({
    runtime:  options.runtime,
    session:  options.session,
    resolver: options.resolver,
    context,
    policy,
    logger:   options.logger,
    metrics:  options.metrics,
    clock:    options.clock,
  });
}

/**
 * @module orchestrator
